<script setup lang="ts">
import { ref } from 'vue'
import { UserCircle, Settings, Upload } from 'lucide-vue-next'
import { API_BASE_URL, API_ENDPOINTS } from '@/config/api'
import { toast } from '@/composables/useToast'

const props = defineProps<{
  name: string
  company: string
  department: string
  phone: string
  email: string
  avatar: string
  loading: boolean
  error: string
}>()

const emit = defineEmits<{
  (e: 'update:name', value: string): void
  (e: 'update:company', value: string): void
  (e: 'update:department', value: string): void
  (e: 'update:phone', value: string): void
  (e: 'update:email', value: string): void
  (e: 'update:avatar', value: string): void
}>()

const uploading = ref(false)
const fileInput = ref<HTMLInputElement>()

const getAuthHeaders = () => {
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return null
  return { uid, token }
}

const triggerUpload = () => {
  fileInput.value?.click()
}

const handleFileChange = async (e: Event) => {
  const target = e.target as HTMLInputElement
  const file = target.files?.[0]
  if (!file) return

  uploading.value = true
  try {
    const auth = getAuthHeaders()
    if (!auth) {
      toast.error('请先登录')
      return
    }

    const tokenRes = await fetch(`${API_BASE_URL}${API_ENDPOINTS.user.avatar}/token`, {
      method: 'GET',
      headers: { 'uid': auth.uid, 'token': auth.token },
    })
    const tokenData = await tokenRes.json()
    if (tokenData.code !== 0) {
      toast.error(tokenData.echo || '获取上传地址失败')
      return
    }

    const uploadUrl = tokenData.data.upload_url
    const formData = new FormData()
    formData.append('file', file)

    const uploadRes = await fetch(uploadUrl, {
      method: 'POST',
      body: formData,
    })
    const uploadData = await uploadRes.json()
    if (uploadData.code !== 0) {
      toast.error(uploadData.echo || '文件上传失败')
      return
    }

    const hash = uploadData.data.hash || uploadData.data
    const params = new URLSearchParams()
    params.append('hash', hash)

    const saveRes = await fetch(`${API_BASE_URL}${API_ENDPOINTS.user.avatar}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'uid': auth.uid,
        'token': auth.token,
      },
      body: params.toString(),
    })
    const saveData = await saveRes.json()
    if (saveData.code === 0) {
      const avatarUrl = saveData.data || (saveData.data.url || saveData.data.Url) || ''
      emit('update:avatar', String(avatarUrl))
      toast.success('头像更新成功')
    } else {
      toast.error(saveData.echo || '保存头像失败')
    }
  } catch (e) {
    console.error('[avatarUpload] 异常', e)
    toast.error('头像上传失败')
  } finally {
    uploading.value = false
    if (target) target.value = ''
  }
}
</script>

<template>
  <div v-if="error" class="mb-4 px-4 py-3 bg-red-50 border border-red-200 text-red-700 text-sm">
    {{ error }}
  </div>
  <div v-if="loading" class="mb-4 px-4 py-3 bg-blue-50 border border-blue-200 text-blue-700 text-sm">
    正在加载个人信息...
  </div>
  <div class="flex items-center gap-6 mb-8">
    <div class="relative">
      <div class="w-20 h-20 bg-gradient-to-br from-flame-500 to-orange-500 flex items-center justify-center overflow-hidden">
        <img v-if="avatar" :src="avatar" class="w-full h-full object-cover" alt="avatar" />
        <UserCircle v-else class="w-10 h-10 text-white" />
      </div>
      <input
        ref="fileInput"
        type="file"
        accept="image/*"
        class="hidden"
        @change="handleFileChange"
      />
      <button
        class="absolute -bottom-1 -right-1 w-8 h-8 bg-white border-2 border-gray-200 flex items-center justify-center hover:border-flame-500 transition-colors"
        :disabled="uploading"
        @click="triggerUpload"
      >
        <Upload v-if="uploading" class="w-4 h-4 text-flame-500 animate-pulse" />
        <Settings v-else class="w-4 h-4 text-gray-500" />
      </button>
    </div>
    <div>
      <h3 class="text-lg font-semibold text-gray-900">{{ name || '未设置' }}</h3>
      <p class="text-sm text-gray-500">个人账号</p>
    </div>
  </div>

  <div class="grid grid-cols-1 md:grid-cols-2 gap-6">
    <div>
      <label class="block text-sm font-medium text-gray-700 mb-2">姓名</label>
      <input
        :value="name"
        @input="emit('update:name', ($event.target as HTMLInputElement).value)"
        type="text"
        class="w-full px-4 py-3 bg-white border border-gray-300 focus:outline-none focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500"
      />
    </div>
    <div>
      <label class="block text-sm font-medium text-gray-700 mb-2">公司</label>
      <input
        :value="company"
        @input="emit('update:company', ($event.target as HTMLInputElement).value)"
        type="text"
        class="w-full px-4 py-3 bg-white border border-gray-300 focus:outline-none focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500"
      />
    </div>
    <div>
      <label class="block text-sm font-medium text-gray-700 mb-2">部门</label>
      <input
        :value="department"
        @input="emit('update:department', ($event.target as HTMLInputElement).value)"
        type="text"
        class="w-full px-4 py-3 bg-white border border-gray-300 focus:outline-none focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500"
      />
    </div>
    <div>
      <label class="block text-sm font-medium text-gray-700 mb-2">手机号</label>
      <input
        :value="phone"
        @input="emit('update:phone', ($event.target as HTMLInputElement).value)"
        type="tel"
        class="w-full px-4 py-3 bg-white border border-gray-300 focus:outline-none focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500"
      />
    </div>
    <div>
      <label class="block text-sm font-medium text-gray-700 mb-2">邮箱</label>
      <input
        :value="email"
        @input="emit('update:email', ($event.target as HTMLInputElement).value)"
        type="email"
        class="w-full px-4 py-3 bg-white border border-gray-300 focus:outline-none focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500"
      />
    </div>
  </div>
</template>