<script setup lang="ts">
import { ref, onMounted, inject } from 'vue'
import { Eye, EyeOff, User, Lock, ShieldCheck } from 'lucide-vue-next'
import { useRouter } from 'vue-router'
import { animate, stagger } from 'animejs'
import { API_BASE_URL, API_ENDPOINTS } from '../config/api'

const refreshHeader = inject<() => void>('refreshHeader')

const router = useRouter()

const formData = ref({
  username: '',
  password: '',
  ident: '',
  code: '',
})

const showPassword = ref(false)
const isLoading = ref(false)
const errorMessage = ref('')
const captchaImage = ref('')

const validateForm = () => {
  if (!formData.value.username.trim()) {
    errorMessage.value = '请输入用户名'
    return false
  }
  if (!formData.value.password) {
    errorMessage.value = '请输入密码'
    return false
  }
  if (!formData.value.code) {
    errorMessage.value = '请输入验证码'
    return false
  }
  errorMessage.value = ''
  return true
}

const fetchCaptcha = async () => {
  try {
    const response = await fetch(API_BASE_URL + API_ENDPOINTS.captcha.create, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
    })
    const result = await response.json()
    if (result.code === 0) {
      formData.value.ident = result.data.ident
      captchaImage.value = 'data:image/gif;base64,' + result.data.image
    }
  } catch (error) {
    console.error('获取验证码失败:', error)
  }
}

const handleLogin = async () => {
  if (!validateForm()) return

  isLoading.value = true
  errorMessage.value = ''

  try {
    const response = await fetch(API_BASE_URL + API_ENDPOINTS.user.login, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: new URLSearchParams({
        username: formData.value.username,
        password: formData.value.password,
        ident: formData.value.ident,
        code: formData.value.code,
      }),
    })

    const result = await response.json()

    if (result.code === 0) {
      if (result.data) {
        localStorage.setItem('uid', String(result.data.id || ''))
        localStorage.setItem('token', String(result.data.token || ''))
      }
      refreshHeader?.()
      animate('.login-card', {
        scale: [1, 0.95],
        opacity: [1, 0],
        duration: 400,
        easing: 'easeInQuad',
        onComplete: () => {
          router.push('/')
        }
      })
    } else {
      errorMessage.value = result.echo || '登录失败'
      shakeForm()
      fetchCaptcha()
    }
  } catch (error) {
    errorMessage.value = '登录失败，请稍后重试'
    shakeForm()
  } finally {
    isLoading.value = false
  }
}

const shakeForm = () => {
  animate('.login-card', {
    translateX: [0, -10, 10, -10, 10, 0],
    duration: 500,
    easing: 'easeInOutSine'
  })
}

onMounted(() => {
  fetchCaptcha()

  animate('.login-bg-orb', {
    scale: [0.8, 1],
    opacity: [0, 1],
    duration: 1200,
    easing: 'easeOutQuad',
    delay: stagger(200)
  })

  animate('.login-title', {
    translateY: [30, 0],
    opacity: [0, 1],
    duration: 800,
    easing: 'easeOutQuad',
    delay: 300
  })

  animate('.login-card', {
    translateY: [60, 0],
    opacity: [0, 1],
    duration: 800,
    easing: 'easeOutQuad',
    delay: 500
  })

  animate('.login-input-item', {
    translateX: [-20, 0],
    opacity: [0, 1],
    duration: 600,
    easing: 'easeOutQuad',
    delay: stagger(100, { start: 700 })
  })

  animate('.login-btn', {
    scale: [0.9, 1],
    opacity: [0, 1],
    duration: 600,
    easing: 'easeOutBack',
    delay: 1100
  })
})
</script>

<template>
  <div class="min-h-screen bg-gradient-to-br from-flame-50 via-white to-orange-50 dark:from-dark-700 dark:to-dark-600 relative overflow-hidden">
    <div class="absolute top-0 left-0 w-full h-full">
      <div class="login-bg-orb absolute top-1/4 -left-32 w-96 h-96 bg-flame-400/10 rounded-full blur-3xl"></div>
      <div class="login-bg-orb absolute bottom-1/4 -right-32 w-96 h-96 bg-orange-400/10 rounded-full blur-3xl"></div>
      <div class="login-bg-orb absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-gradient-to-br from-flame-500/5 to-transparent rounded-full blur-3xl"></div>
    </div>

    <div class="relative z-10 min-h-screen flex items-center justify-center px-4 py-12 lg:py-20">
      <div class="w-full max-w-md">
        <div class="login-title text-center mb-10">
          <h1 class="text-3xl font-bold text-gray-900 dark:text-white mb-4">账号密码登录</h1>
          <p class="text-gray-500 dark:text-gray-400">欢迎回来，请登录您的账户</p>
        </div>

        <div class="login-card bg-white dark:bg-dark-500/80 backdrop-blur-lg rounded-2xl shadow-xl shadow-gray-200/50 dark:shadow-black/20 p-8 border border-gray-100 dark:border-white/10">
          <form @submit.prevent="handleLogin" class="space-y-5">
            <div v-if="errorMessage" class="login-error">
              <div class="flex items-center gap-2 px-4 py-3 bg-red-50 border border-red-200 rounded-lg text-red-600 dark:bg-red-500/10 dark:border-red-500/30 dark:text-red-400">
                <svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path>
                </svg>
                {{ errorMessage }}
              </div>
            </div>

            <div class="login-input-item relative">
              <div class="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">
                <User class="w-5 h-5" />
              </div>
              <input
                v-model="formData.username"
                type="text"
                placeholder="用户名"
                class="w-full pl-12 pr-4 py-4 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500 dark:bg-dark-400 dark:border-dark-300 dark:text-white transition-all text-gray-900"
              />
            </div>

            <div class="login-input-item relative">
              <div class="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">
                <Lock class="w-5 h-5" />
              </div>
              <input
                v-model="formData.password"
                :type="showPassword ? 'text' : 'password'"
                placeholder="密码"
                class="w-full pl-12 pr-12 py-4 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500 dark:bg-dark-400 dark:border-dark-300 dark:text-white transition-all text-gray-900"
              />
              <button
                type="button"
                @click="showPassword = !showPassword"
                class="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 dark:text-gray-500 dark:hover:text-gray-300 transition-colors"
              >
                <Eye v-if="showPassword" class="w-5 h-5" />
                <EyeOff v-else class="w-5 h-5" />
              </button>
            </div>

            <div class="login-input-item relative flex gap-3">
              <div class="relative flex-1">
                <div class="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">
                  <ShieldCheck class="w-5 h-5" />
                </div>
                <input
                  v-model="formData.code"
                  type="text"
                  placeholder="验证码"
                  class="w-full pl-12 pr-4 py-4 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500 dark:bg-dark-400 dark:border-dark-300 dark:text-white transition-all text-gray-900"
                />
              </div>
              <img
                v-if="captchaImage"
                @click="fetchCaptcha"
                :src="captchaImage"
                alt="验证码"
                class="w-42 h-[58px] rounded-xl cursor-pointer hover:ring-2 hover:ring-flame-500/50 transition-all object-cover object-center"
              />
              <div
                v-else
                @click="fetchCaptcha"
                class="w-42 h-[58px] rounded-xl cursor-pointer border border-gray-200 dark:border-dark-300 hover:border-flame-500 transition-colors flex items-center justify-center bg-gray-50 dark:bg-dark-400"
              >
                <span class="text-xs text-gray-400">点击刷新</span>
              </div>
            </div>

            <div class="flex items-center justify-between">
              <label class="flex items-center gap-2 cursor-pointer">
                <input
                  type="checkbox"
                  class="w-4 h-4 text-flame-500 border-gray-300 rounded focus:ring-flame-500 dark:bg-dark-400 dark:border-dark-300"
                />
                <span class="text-sm text-gray-600 dark:text-gray-400">记住我</span>
              </label>
              <router-link to="/forget" class="text-sm text-flame-500 hover:text-flame-600 dark:text-flame-400 transition-colors">忘记密码?</router-link>
            </div>

            <button
              type="submit"
              :disabled="isLoading"
              class="login-btn w-full bg-gradient-to-r from-flame-500 to-orange-500 text-white py-4 rounded-xl font-semibold text-base hover:shadow-lg hover:shadow-flame-500/25 transition-all duration-300 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              <span v-if="isLoading" class="flex items-center justify-center gap-2">
                <span class="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
                登录中...
              </span>
              <span v-else>立即登录</span>
            </button>
          </form>

          <div class="mt-6 pt-6 border-t border-gray-100 dark:border-white/10">
            <p class="text-center text-sm text-gray-500 dark:text-gray-400">
              还没有账户？
              <router-link to="/register" class="text-flame-500 hover:text-flame-600 dark:text-flame-400 font-medium transition-colors">免费注册</router-link>
            </p>
          </div>
        </div>

        <p class="mt-8 text-center text-sm text-gray-400 dark:text-gray-500">
          © 2024 火焰云. 保留所有权利.
        </p>
      </div>
    </div>
  </div>
</template>