<script setup lang="ts">
import { ref, onMounted, onUnmounted } from 'vue'
import { Users, Rocket, Heart } from 'lucide-vue-next'
import SectionTitle from '@/components/SectionTitle.vue'
import { animate, set } from 'animejs'

const benefits = [
  { icon: Rocket, title: '成长空间', desc: '完善的培训和晋升通道，助力职业发展' },
  { icon: Heart, title: '福利保障', desc: '五险一金、节日福利、团建活动' },
  { icon: Users, title: '团队氛围', desc: '开放包容的团队文化，扁平化管理' },
  { icon: Rocket, title: '行业前景', desc: '云计算行业高速发展，前景广阔' },
]

const heroSection = ref<HTMLElement | null>(null)
const benefitsSection = ref<HTMLElement | null>(null)
const contactSection = ref<HTMLElement | null>(null)

const heroTitleChars = ref<string[]>([])
const heroSubtitleChars = ref<string[]>([])
const isHeroAnimating = ref(false)

let heroObserver: IntersectionObserver | null = null
let benefitsObserver: IntersectionObserver | null = null
let contactObserver: IntersectionObserver | null = null

const animateHero = () => {
  if (!heroSection.value) return
  
  const heroContent = heroSection.value.querySelector('.hero-content')
  
  if (heroContent) {
    set(heroContent as HTMLElement, {
      opacity: 0,
      translateY: 50
    })
    
    animate(heroContent as HTMLElement, {
      opacity: [0, 1],
      translateY: [50, 0],
      duration: 1000,
      easing: 'easeOutCubic'
    })
  }
  
  heroTitleChars.value = '加入火焰云'.split('')
  heroSubtitleChars.value = '与优秀的人一起，做有价值的事'.split('')
  
  setTimeout(() => {
    isHeroAnimating.value = true
  }, 100)
}

const animateBenefits = () => {
  if (!benefitsSection.value) return
  
  const benefitCards = benefitsSection.value.querySelectorAll('.benefit-card')
  
  benefitCards.forEach((card, index) => {
    set(card as HTMLElement, {
      opacity: 0,
      translateY: 40,
      scale: 0.9
    })
    
    animate(card as HTMLElement, {
      opacity: [0, 1],
      translateY: [40, 0],
      scale: [0.9, 1],
      duration: 800,
      delay: index * 150,
      easing: 'easeOutBack'
    })
  })
}

const animateContact = () => {
  if (!contactSection.value) return
  
  const contactCard = contactSection.value.querySelector('.contact-card')
  
  if (contactCard) {
    set(contactCard as HTMLElement, {
      opacity: 0,
      translateY: 30
    })
    
    animate(contactCard as HTMLElement, {
      opacity: [0, 1],
      translateY: [30, 0],
      duration: 800,
      easing: 'easeOutCubic'
    })
  }
}

onMounted(() => {
  heroObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          animateHero()
        } else {
          isHeroAnimating.value = false
          heroTitleChars.value = []
          heroSubtitleChars.value = []
        }
      })
    },
    { threshold: 0.3 }
  )
  
  benefitsObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          animateBenefits()
        }
      })
    },
    { threshold: 0.2 }
  )
  
  contactObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          animateContact()
        }
      })
    },
    { threshold: 0.3 }
  )
  
  if (heroSection.value) {
    heroObserver.observe(heroSection.value)
  }
  
  if (benefitsSection.value) {
    benefitsObserver.observe(benefitsSection.value)
  }
  
  if (contactSection.value) {
    contactObserver.observe(contactSection.value)
  }
})

onUnmounted(() => {
  if (heroObserver && heroSection.value) {
    heroObserver.unobserve(heroSection.value)
  }
  if (benefitsObserver && benefitsSection.value) {
    benefitsObserver.unobserve(benefitsSection.value)
  }
  if (contactObserver && contactSection.value) {
    contactObserver.unobserve(contactSection.value)
  }
})
</script>

<template>
  <div class="min-h-screen pt-12 lg:pt-14">
    <!-- Hero -->
    <section ref="heroSection" class="relative overflow-hidden">
      <div class="absolute inset-0">
        <img src="@/assets/images/公司简介.dfa0ef11.jpg" alt="加入火焰云" class="w-full h-full object-cover" />
        <div class="absolute inset-0 bg-gradient-to-r from-black/50 via-black/30 to-transparent dark:from-dark-600/80 dark:via-dark-600/60"></div>
      </div>
      <div class="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16 lg:py-24">
        <div class="hero-content max-w-3xl">
          <h1 class="text-3xl lg:text-4xl font-bold text-white mb-4">
            <span
              v-for="(char, index) in heroTitleChars"
              :key="'hero-title-' + index"
              :class="['inline-block char-type', isHeroAnimating ? 'animate' : '']"
              :style="{ animationDelay: `${index * 50}ms` }"
            >{{ char }}</span>
          </h1>
          <p class="text-white/80 text-lg leading-relaxed">
            <span
              v-for="(char, index) in heroSubtitleChars"
              :key="'hero-subtitle-' + index"
              :class="['inline-block char-type-desc', isHeroAnimating ? 'animate' : '']"
              :style="{ animationDelay: `${(heroTitleChars.length + index) * 30}ms` }"
            >{{ char }}</span>
          </p>
        </div>
      </div>
    </section>

    <!-- Benefits -->
    <section ref="benefitsSection" class="section-padding">
      <div class="max-w-7xl mx-auto">
        <SectionTitle title="为什么加入我们" center />
        <div class="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          <div v-for="benefit in benefits" :key="benefit.title" class="benefit-card glass-card p-6 text-center">
            <div class="w-14 h-14 rounded-xl bg-flame-50 dark:bg-flame-500/10 flex items-center justify-center mx-auto mb-4">
              <component :is="benefit.icon" class="w-7 h-7 text-flame-500" />
            </div>
            <h3 class="text-gray-900 dark:text-white font-semibold mb-2">{{ benefit.title }}</h3>
            <p class="text-gray-500 dark:text-gray-400 text-sm">{{ benefit.desc }}</p>
          </div>
        </div>
      </div>
    </section>

    <!-- Contact -->
    <section ref="contactSection" class="section-padding">
      <div class="max-w-2xl mx-auto text-center">
        <SectionTitle title="联系我们" subtitle="期待你的加入" center />
        <div class="contact-card glass-card p-8 mt-8">
          <p class="text-gray-600 dark:text-gray-300 mb-4">发送简历至：</p>
          <p class="text-flame-500 text-lg font-semibold">hr@flamecloud.cn</p>
          <p class="text-gray-500 dark:text-gray-400 text-sm mt-4">微信：FlameCloud_HR</p>
        </div>
      </div>
    </section>
  </div>
</template>

<style scoped>
.char-type {
  opacity: 0;
  transform: translateY(-20px);
  filter: blur(4px);
}

.char-type.animate {
  animation: charReveal 0.4s ease-out forwards;
}

@keyframes charReveal {
  0% {
    opacity: 0;
    transform: translateY(-20px);
    filter: blur(4px);
  }
  100% {
    opacity: 1;
    transform: translateY(0);
    filter: blur(0);
  }
}

.char-type-desc {
  opacity: 0;
  transform: translateX(-10px);
}

.char-type-desc.animate {
  animation: charSlideIn 0.3s ease-out forwards;
}

@keyframes charSlideIn {
  0% {
    opacity: 0;
    transform: translateX(-10px);
  }
  100% {
    opacity: 1;
    transform: translateX(0);
  }
}
</style>