<script setup lang="ts">
import { ref } from 'vue'
import { Copy, Eye, EyeOff, X } from 'lucide-vue-next'
import { API_BASE_URL, API_ENDPOINTS } from '@/config/api'
import { toast } from '@/composables/useToast'

const props = defineProps<{
  show: boolean
}>()

const emit = defineEmits<{
  (e: 'close'): void
  (e: 'created'): void
}>()

const newAkName = ref('')
const newAkSecret = ref('')
const newAkKey = ref('')
const showSecret = ref(false)

const getAuthHeaders = () => {
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return null
  return { uid, token }
}

const createAk = async () => {
  const auth = getAuthHeaders()
  if (!auth) return
  const params = new URLSearchParams()
  params.append('action', 'create')
  params.append('name', newAkName.value)
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.accessKey.list}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'uid': auth.uid, 'token': auth.token },
      body: params.toString(),
    })
    const data = await res.json()
    if (data.code === 0) {
      newAkKey.value = data.data.access_key
      newAkSecret.value = data.data.access_secret
      showSecret.value = false
    } else {
      toast.error(data.echo || '创建失败')
    }
  } catch (e) {
    console.error('[createAk]', e)
    toast.error('创建失败')
  }
}

const reset = () => {
  newAkName.value = ''
  newAkKey.value = ''
  newAkSecret.value = ''
  showSecret.value = false
}

const close = () => {
  reset()
  emit('close')
}

const closeAndRefresh = () => {
  reset()
  emit('created')
  emit('close')
}

const copyToClipboard = async (text: string) => {
  try {
    await navigator.clipboard.writeText(text)
    toast.success('已复制')
  } catch {
    toast.error('复制失败')
  }
}
</script>

<template>
  <Teleport to="body">
    <div v-if="show" class="fixed inset-0 z-50 flex items-center justify-center">
      <div class="absolute inset-0 bg-black/40" @click="close"></div>
      <div class="relative bg-white rounded-xl shadow-2xl w-full max-w-lg mx-4 p-6">
        <button @click="close" class="absolute top-4 right-4 text-gray-400 hover:text-gray-600"><X class="w-5 h-5" /></button>
        <h3 class="text-lg font-semibold text-gray-900 mb-4">创建 AccessKey</h3>

        <template v-if="!newAkKey">
          <div class="mb-4">
            <label class="block text-sm font-medium text-gray-700 mb-1">备注名称</label>
            <input v-model="newAkName" class="w-full px-4 py-3 border border-gray-300 focus:outline-none focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500" placeholder="例如：生产环境、开发测试" />
          </div>
          <div class="flex justify-end gap-3">
            <button @click="close" class="px-4 py-2 text-sm text-gray-700 bg-gray-100 hover:bg-gray-200">取消</button>
            <button @click="createAk" class="flame-btn px-4 py-2 text-sm">确认创建</button>
          </div>
        </template>

        <template v-else>
          <div class="bg-amber-50 border border-amber-200 rounded-lg p-3 mb-4 text-sm text-amber-700">
            ⚠️ AccessSecret 仅在创建时显示一次，请立即复制保存，关闭后将无法找回。
          </div>
          <div class="mb-3">
            <label class="block text-xs text-gray-500 mb-1">AccessKey</label>
            <div class="flex items-center gap-2">
              <code class="flex-1 px-3 py-2 bg-gray-50 text-sm font-mono break-all text-gray-900">{{ newAkKey }}</code>
              <button @click="copyToClipboard(newAkKey)" class="text-gray-400 hover:text-gray-600"><Copy class="w-4 h-4" /></button>
            </div>
          </div>
          <div class="mb-4">
            <label class="block text-xs text-gray-500 mb-1">AccessSecret</label>
            <div class="flex items-center gap-2">
              <code class="flex-1 px-3 py-2 bg-gray-50 text-sm font-mono break-all text-gray-900">{{ showSecret ? newAkSecret : '••••••••••••••••••••••••••••••••' }}</code>
              <button @click="showSecret = !showSecret" class="text-gray-400 hover:text-gray-600">
                <Eye v-if="!showSecret" class="w-4 h-4" />
                <EyeOff v-else class="w-4 h-4" />
              </button>
              <button @click="copyToClipboard(newAkSecret)" class="text-gray-400 hover:text-gray-600"><Copy class="w-4 h-4" /></button>
            </div>
          </div>
          <div class="flex justify-end">
            <button @click="closeAndRefresh" class="flame-btn px-4 py-2 text-sm">我已保存，关闭</button>
          </div>
        </template>
      </div>
    </div>
  </Teleport>
</template>