<script setup lang="ts">
import { ref, onMounted } from 'vue'
import { ChevronLeft, ChevronRight, ArrowLeft } from 'lucide-vue-next'
import { useRouter } from 'vue-router'
import { API_BASE_URL, API_ENDPOINTS } from '@/config/api'

interface LogItem {
  id: number
  ak_id: number
  uid: number
  action: string
  detail: string
  ip: string
  created_at: string
}

const router = useRouter()
const logs = ref<LogItem[]>([])
const loading = ref(false)
const page = ref(1)

const getAuthHeaders = () => {
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return null
  return { uid, token }
}

const fetchLogs = async (p: number = 1) => {
  const auth = getAuthHeaders()
  if (!auth) return
  loading.value = true
  page.value = p
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.accessKey.logAll}?page=${p}`, {
      headers: { 'uid': auth.uid, 'token': auth.token },
    })
    const data = await res.json()
    if (data.code === 0) {
      logs.value = data.data || []
    }
  } catch (e) {
    console.error('[fetchLogs]', e)
  } finally {
    loading.value = false
  }
}

const formatTime = (t: string) => {
  if (!t) return '-'
  return t.replace('T', ' ').substring(0, 19)
}

const actionBadgeClass = (action: string) => {
  const map: Record<string, string> = {
    create: 'bg-green-100 text-green-700',
    delete: 'bg-red-100 text-red-700',
    permission: 'bg-purple-100 text-purple-700',
    update: 'bg-blue-100 text-blue-700',
  }
  return map[action] || 'bg-gray-100 text-gray-600'
}

const goBack = () => {
  router.push('/console/users')
}

onMounted(() => {
  fetchLogs()
})
</script>

<template>
  <div class="p-6">
    <div class="flex items-center gap-3 mb-6">
      <button @click="goBack" class="text-gray-400 hover:text-gray-600">
        <ArrowLeft class="w-5 h-5" />
      </button>
      <div>
        <h1 class="text-2xl font-bold text-gray-900">AK 日志</h1>
        <p class="text-gray-500 mt-1">所有 AccessKey 的操作记录</p>
      </div>
    </div>

    <div class="bg-white border border-gray-200">
      <table class="w-full" v-if="!loading">
        <thead>
          <tr class="border-b border-gray-200 bg-gray-50">
            <th class="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">时间</th>
            <th class="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">AK ID</th>
            <th class="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">操作</th>
            <th class="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">详情</th>
            <th class="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">IP</th>
          </tr>
        </thead>
        <tbody>
          <tr v-if="logs.length === 0">
            <td colspan="5" class="px-4 py-12 text-center text-gray-400">暂无操作日志</td>
          </tr>
          <tr v-for="log in logs" :key="log.id" class="border-b border-gray-100 hover:bg-gray-50 transition-colors">
            <td class="px-4 py-3 text-sm text-gray-600">{{ formatTime(log.created_at) }}</td>
            <td class="px-4 py-3 text-sm text-gray-600 font-mono">{{ log.ak_id }}</td>
            <td class="px-4 py-3">
              <span :class="['px-2 py-0.5 text-xs font-medium', actionBadgeClass(log.action)]">
                {{ log.action }}
              </span>
            </td>
            <td class="px-4 py-3 text-sm text-gray-600">{{ log.detail }}</td>
            <td class="px-4 py-3 text-sm text-gray-500 font-mono">{{ log.ip }}</td>
          </tr>
        </tbody>
      </table>
      <div v-else class="px-4 py-12 text-center text-gray-400">加载中...</div>
    </div>

    <div class="flex items-center justify-center gap-4 mt-4">
      <button @click="fetchLogs(page - 1)" :disabled="page <= 1" class="px-3 py-1 text-sm text-gray-600 hover:bg-gray-100 disabled:opacity-30 disabled:cursor-not-allowed">
        <ChevronLeft class="w-4 h-4" />
      </button>
      <span class="text-sm text-gray-500">第 {{ page }} 页</span>
      <button @click="fetchLogs(page + 1)" :disabled="logs.length < 20" class="px-3 py-1 text-sm text-gray-600 hover:bg-gray-100 disabled:opacity-30 disabled:cursor-not-allowed">
        <ChevronRight class="w-4 h-4" />
      </button>
    </div>
  </div>
</template>