<script setup lang="ts">
import { ref, onMounted, watch } from 'vue'
import { useRoute } from 'vue-router'
import { ChevronLeft, ChevronRight } from 'lucide-vue-next'
import { API_BASE_URL, API_ENDPOINTS } from '@/config/api'

interface LogItem {
  id: number
  uid: number
  log_type_id: number
  action: string
  detail: string
  ip: string
  created_at: string
}

interface LogType {
  id: number
  name: string
  code: string
}

const route = useRoute()

const logs = ref<LogItem[]>([])
const logTypes = ref<LogType[]>([])
const loading = ref(false)
const page = ref(1)
const pageSize = 20
const total = ref(0)
const activeTypeId = ref<string>('')

const getAuthHeaders = () => {
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return null
  return { uid, token }
}

const fetchLogTypes = async () => {
  const auth = getAuthHeaders()
  if (!auth) return
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.actionLog.type}`, {
      headers: { 'uid': auth.uid, 'token': auth.token },
    })
    const data = await res.json()
    if (data.code === 0) {
      logTypes.value = data.data || []
    }
  } catch (e) {
    console.error('[fetchLogTypes]', e)
  }
}

const fetchLogs = async (p: number = 1) => {
  const auth = getAuthHeaders()
  if (!auth) return
  loading.value = true
  page.value = p
  try {
    let url = `${API_BASE_URL}${API_ENDPOINTS.actionLog.list}?page=${p}&page_size=${pageSize}`
    if (activeTypeId.value) {
      url += `&log_type_id=${activeTypeId.value}`
    }
    const res = await fetch(url, {
      headers: { 'uid': auth.uid, 'token': auth.token },
    })
    const data = await res.json()
    if (data.code === 0) {
      logs.value = data.data.list || []
      total.value = data.data.total || 0
    }
  } catch (e) {
    console.error('[fetchLogs]', e)
  } finally {
    loading.value = false
  }
}

watch(() => route.query.log_type_id, (newVal) => {
  activeTypeId.value = newVal ? String(newVal) : ''
  page.value = 1
  fetchLogs(1)
})

const getTypeName = (logTypeId: number) => {
  const t = logTypes.value.find(item => item.id === logTypeId)
  return t ? t.name : '未知'
}

const getTypeCode = (logTypeId: number) => {
  const t = logTypes.value.find(item => item.id === logTypeId)
  return t ? t.code : 'unknown'
}

const formatTime = (t: string) => {
  if (!t) return '-'
  return t.replace('T', ' ').substring(0, 19)
}

const actionBadgeClass = (code: string) => {
  const map: Record<string, string> = {
    user: 'bg-blue-100 text-blue-700',
    system: 'bg-yellow-100 text-yellow-700',
    ak: 'bg-purple-100 text-purple-700',
  }
  return map[code] || 'bg-gray-100 text-gray-600'
}

const totalPages = ref(0)

watch(() => total.value, (val) => {
  totalPages.value = Math.ceil(val / pageSize)
})

onMounted(async () => {
  await fetchLogTypes()
  const initTypeId = route.query.log_type_id
  if (initTypeId) {
    activeTypeId.value = String(initTypeId)
  }
  fetchLogs()
})
</script>

<template>
  <div class="p-6 h-full overflow-y-auto">
    <div class="mb-6">
      <h1 class="text-2xl font-bold text-gray-900">操作日志</h1>
      <p class="text-gray-500 mt-1">查看所有操作记录</p>
    </div>

    <div class="bg-white border border-gray-200">
      <table class="w-full" v-if="!loading">
        <thead>
          <tr class="border-b border-gray-200 bg-gray-50">
            <th class="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">时间</th>
            <th class="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">类型</th>
            <th class="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">操作</th>
            <th class="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">详情</th>
            <th class="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">IP</th>
          </tr>
        </thead>
        <tbody>
          <tr v-if="logs.length === 0">
            <td colspan="5" class="px-4 py-12 text-center text-gray-400">暂无操作日志</td>
          </tr>
          <tr v-for="log in logs" :key="log.id" class="border-b border-gray-100 hover:bg-gray-50 transition-colors">
            <td class="px-4 py-3 text-sm text-gray-600 whitespace-nowrap">{{ formatTime(log.created_at) }}</td>
            <td class="px-4 py-3">
              <span :class="['px-2 py-0.5 text-xs font-medium', actionBadgeClass(getTypeCode(log.log_type_id))]">
                {{ getTypeName(log.log_type_id) }}
              </span>
            </td>
            <td class="px-4 py-3 text-sm text-gray-600">{{ log.action }}</td>
            <td class="px-4 py-3 text-sm text-gray-600">{{ log.detail }}</td>
            <td class="px-4 py-3 text-sm text-gray-500 font-mono">{{ log.ip }}</td>
          </tr>
        </tbody>
      </table>
      <div v-else class="px-4 py-12 text-center text-gray-400">加载中...</div>
    </div>

    <div class="flex items-center justify-center gap-4 mt-4">
      <button
        @click="fetchLogs(page - 1)"
        :disabled="page <= 1"
        class="px-3 py-1 text-sm text-gray-600 hover:bg-gray-100 disabled:opacity-30 disabled:cursor-not-allowed"
      >
        <ChevronLeft class="w-4 h-4" />
      </button>
      <span class="text-sm text-gray-500">第 {{ page }} / {{ totalPages }} 页 (共 {{ total }} 条)</span>
      <button
        @click="fetchLogs(page + 1)"
        :disabled="page >= totalPages"
        class="px-3 py-1 text-sm text-gray-600 hover:bg-gray-100 disabled:opacity-30 disabled:cursor-not-allowed"
      >
        <ChevronRight class="w-4 h-4" />
      </button>
    </div>
  </div>
</template>