<script setup lang="ts">
import { ref, onMounted, watch } from 'vue'

const props = defineProps<{
  title: string
  subtitle?: string
  center?: boolean
  typing?: boolean
}>()

const displayedTitle = ref('')
const isTyping = ref(false)

const startTyping = () => {
  displayedTitle.value = ''
  isTyping.value = true
  let index = 0
  const typeChar = () => {
    if (index < props.title.length) {
      displayedTitle.value += props.title[index]
      index++
      setTimeout(typeChar, 100)
    } else {
      isTyping.value = false
    }
  }
  typeChar()
}

onMounted(() => {
  if (props.typing) {
    startTyping()
  } else {
    displayedTitle.value = props.title
  }
})

watch(() => props.typing, (newVal) => {
  if (newVal) {
    startTyping()
  } else {
    displayedTitle.value = props.title
  }
})

watch(() => props.title, (newVal) => {
  if (props.typing) {
    startTyping()
  } else {
    displayedTitle.value = newVal
  }
})
</script>

<template>
  <div :class="['mb-12', center && 'text-center']">
    <h2 class="text-2xl lg:text-3xl font-bold text-gray-900 dark:text-white mb-3">
      {{ typing ? displayedTitle : title }}
      <span v-if="typing && isTyping" class="animate-pulse">|</span>
    </h2>
    <p v-if="subtitle" class="text-gray-500 dark:text-gray-400 text-sm lg:text-base">{{ subtitle }}</p>
  </div>
</template>