<script setup lang="ts">
import { ref, computed, watch, onMounted } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { ChevronLeft, ChevronRight, LayoutDashboard, Server, HardDrive, Cloud, Shield, Activity, BarChart3, Users, Settings, Plus, Search, Trash2, ShieldCheck, AlertTriangle, FileText, Clock, Cpu, HardDrive as Disk, Zap, Globe, Key, Bell, TrendingUp, Target, Eye, PieChart, LineChart, UserPlus, Lock, ClipboardList, User, LogIn, ShieldAlert, Layers, HelpCircle } from 'lucide-vue-next'
import { API_BASE_URL, API_ENDPOINTS } from '@/config/api'

const route = useRoute()
const router = useRouter()
const collapsed = ref(false)
const logTypes = ref<{ id: number; name: string; code: string }[]>([])

const typeIconMap: Record<string, any> = {
  user: User,
  system: Shield,
  ak: Settings,
  login: LogIn,
  security: ShieldAlert,
}

const activeSubKey = computed(() => {
  const path = route.path
  const module = currentModule.value
  const menus = currentSubMenus.value
  if (menus && menus.length > 0) {
    if (module === 'logs') {
      const typeId = route.query.log_type_id
      if (typeId) {
        const matched = menus.find(m => m.key === String(typeId))
        if (matched) return matched.key
      }
      return 'all'
    }
    if (module === 'ecs') {
      const tab = route.query.tab
      if (tab) {
        const matched = menus.find(m => m.key === String(tab))
        if (matched) return matched.key
      }
      return 'instances'
    }
    if (module === 'oss') {
      const tab = route.query.tab
      if (tab) {
        const matched = menus.find(m => m.key === String(tab))
        if (matched) return matched.key
      }
      return 'buckets'
    }
    const matched = menus.find(m => m.path === path)
    if (matched) return matched.key
    return menus[0].key
  }
  return ''
})

const staticSubMenus: Record<string, { key: string; name: string; icon: any; path?: string }[]> = {
  dashboard: [
    { key: 'overview', name: '资源概览', icon: LayoutDashboard, path: '/console/dashboard' },
    { key: 'notification', name: '消息中心', icon: Bell, path: '/console/notification' },
  ],
  ecs: [
    { key: 'instances', name: '实例列表', icon: Server, path: '/console/ecs?tab=instances' },
    { key: 'images', name: '镜像管理', icon: FileText, path: '/console/ecs?tab=images' },
    { key: 'security-group', name: '安全组', icon: ShieldCheck, path: '/console/ecs?tab=security-group' },
    { key: 'keypairs', name: '密钥对', icon: Key, path: '/console/ecs?tab=keypairs' },
    { key: 'snapshots', name: '快照管理', icon: FileText, path: '/console/ecs?tab=snapshots' },
  ],
  oss: [
    { key: 'buckets', name: '存储桶列表', icon: HardDrive, path: '/console/oss?tab=buckets' },
    { key: 'files', name: '文件管理', icon: Search, path: '/console/oss?tab=files' },
    { key: 'access', name: '访问控制', icon: ShieldCheck, path: '/console/oss?tab=access' },
    { key: 'cors', name: '跨域设置', icon: Globe, path: '/console/oss?tab=cors' },
    { key: 'recycle', name: '回收站', icon: Trash2, path: '/console/oss?tab=recycle' },
  ],
  monitor: [
    { key: 'panel', name: '监控面板', icon: Activity, path: '/console/monitor' },
    { key: 'alerts', name: '告警策略', icon: Bell, path: '/console/monitor' },
    { key: 'history', name: '告警历史', icon: Clock, path: '/console/monitor' },
    { key: 'metrics', name: '指标管理', icon: LineChart, path: '/console/monitor' },
  ],
  analytics: [
    { key: 'business', name: '业务概览', icon: PieChart, path: '/console/analytics' },
    { key: 'users', name: '用户分析', icon: Users, path: '/console/analytics' },
    { key: 'traffic', name: '流量分析', icon: TrendingUp, path: '/console/analytics' },
    { key: 'reports', name: '报表中心', icon: FileText, path: '/console/analytics' },
  ],
  users: [
    { key: 'list', name: 'AK列表', icon: Users, path: '/console/users' },
    { key: 'logs', name: 'AK日志', icon: ClipboardList, path: '/console/users/logs' },
  ],
  settings: [
    { key: 'profile', name: '个人信息', icon: UserPlus, path: '/console/settings/profile' },
    { key: 'security', name: '安全设置', icon: Shield, path: '/console/settings/security' },
    { key: 'notification', name: '通知设置', icon: Bell, path: '/console/settings/notification' },
    { key: 'help', name: '帮助中心', icon: HelpCircle, path: '/console/help' },
  ],
}

const currentSubMenus = computed(() => {
  if (currentModule.value === 'logs') {
    const logMenu: { key: string; name: string; icon: any; path?: string }[] = [
      { key: 'all', name: '综合', icon: Layers, path: '/console/logs' },
    ]
    logTypes.value.forEach(type => {
      logMenu.push({
        key: String(type.id),
        name: type.name,
        icon: typeIconMap[type.code] || FileText,
        path: `/console/logs?log_type_id=${type.id}`,
      })
    })
    return logMenu
  }
  return staticSubMenus[currentModule.value] || []
})

const getAuthHeaders = () => {
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return null
  return { uid, token }
}

const fetchLogTypes = async () => {
  const auth = getAuthHeaders()
  if (!auth) return
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.actionLog.type}`, {
      headers: { 'uid': auth.uid, 'token': auth.token },
    })
    const data = await res.json()
    if (data.code === 0) {
      logTypes.value = data.data || []
    }
  } catch (e) {
    console.error('[fetchLogTypes]', e)
  }
}

const currentModule = computed(() => {
  const path = route.path
  if (path.startsWith('/console/dashboard')) return 'dashboard'
  if (path.startsWith('/console/notification')) return 'dashboard'
  if (path.startsWith('/console/ecs')) return 'ecs'
  if (path.startsWith('/console/oss')) return 'oss'
  if (path.startsWith('/console/monitor')) return 'monitor'
  if (path.startsWith('/console/analytics')) return 'analytics'
  if (path.startsWith('/console/users')) return 'users'
  if (path.startsWith('/console/logs')) return 'logs'
  if (path.startsWith('/console/settings')) return 'settings'
  if (path.startsWith('/console/help')) return 'settings'
  return 'dashboard'
})

const moduleTitle: Record<string, string> = {
  dashboard: '控制台',
  ecs: '云服务器',
  oss: '对象存储',
  monitor: '监控告警',
  analytics: '数据分析',
  users: 'AK管理',
  settings: '账号设置',
  logs: '操作日志',
}

watch(currentModule, () => {
})

onMounted(() => {
  fetchLogTypes()
})

const handleSubMenuClick = (item: { path?: string; key: string }) => {
  if (item.path) {
    if (item.path.includes('?')) {
      const [path, queryString] = item.path.split('?')
      const params = new URLSearchParams(queryString)
      const query: Record<string, string> = {}
      params.forEach((value, key) => { query[key] = value })
      router.push({ path, query })
    } else {
      router.push(item.path)
    }
  }
}

const toggleSidebar = () => {
  collapsed.value = !collapsed.value
}

defineExpose({
  collapsed,
  toggleSidebar
})
</script>

<template>
  <aside
    :class="[
      'h-full bg-[#202020] text-white flex flex-col transition-all duration-300 flex-shrink-0',
      collapsed ? 'w-16' : 'w-[199px]'
    ]"
  >
    <div class="px-5 pt-4 pb-3 border-b border-gray-800 flex-shrink-0">
      <span v-if="!collapsed" class="text-lg font-bold text-white">{{ moduleTitle[currentModule] }}</span>
    </div>

    <nav class="flex-1 py-4 overflow-y-auto">
      <ul class="space-y-1 px-2">
        <li v-for="item in currentSubMenus" :key="item.key">
          <button
            @click="handleSubMenuClick(item)"
            :class="[
              'w-full flex items-center gap-3 px-3 py-2.5 transition-all duration-200',
              activeSubKey === item.key
                ? 'bg-flame-500 text-white shadow-lg shadow-flame-500/25'
                : 'text-gray-300 hover:bg-gray-800 hover:text-white'
            ]"
          >
            <component :is="item.icon" class="w-5 h-5 flex-shrink-0" />
            <span v-if="!collapsed" class="text-sm font-medium whitespace-nowrap">{{ item.name }}</span>
          </button>
        </li>
      </ul>
    </nav>
  </aside>
</template>