<script setup lang="ts">
import { ChevronRight } from 'lucide-vue-next'

defineProps<{
  twoFactor: boolean
  loginAlert: boolean
  sessionTimeout: number
}>()

const emit = defineEmits<{
  (e: 'update:twoFactor', value: boolean): void
  (e: 'update:loginAlert', value: boolean): void
  (e: 'update:sessionTimeout', value: number): void
  (e: 'changePassword'): void
}>()
</script>

<template>
  <div class="space-y-4">
    <div class="flex items-center justify-between p-4 bg-gray-50">
      <div>
        <h4 class="font-medium text-gray-900">双因素认证</h4>
        <p class="text-sm text-gray-500">登录时需要额外验证</p>
      </div>
      <div
        @click="emit('update:twoFactor', !twoFactor)"
        role="switch"
        :aria-checked="twoFactor"
        tabindex="0"
        :class="[
          'relative w-12 h-6 rounded-full transition-colors cursor-pointer select-none',
          twoFactor ? 'bg-flame-500' : 'bg-gray-300'
        ]"
      >
        <span
          :class="[
            'absolute top-1 left-1 w-4 h-4 bg-white rounded-full shadow-sm transition-transform',
            twoFactor ? 'translate-x-[24px]' : ''
          ]"
        ></span>
      </div>
    </div>
    <div class="flex items-center justify-between p-4 bg-gray-50">
      <div>
        <h4 class="font-medium text-gray-900">登录提醒</h4>
        <p class="text-sm text-gray-500">异地登录时发送提醒</p>
      </div>
      <div
        @click="emit('update:loginAlert', !loginAlert)"
        role="switch"
        :aria-checked="loginAlert"
        tabindex="0"
        :class="[
          'relative w-12 h-6 rounded-full transition-colors cursor-pointer select-none',
          loginAlert ? 'bg-flame-500' : 'bg-gray-300'
        ]"
      >
        <span
          :class="[
            'absolute top-1 left-1 w-4 h-4 bg-white rounded-full shadow-sm transition-transform',
            loginAlert ? 'translate-x-[24px]' : ''
          ]"
        ></span>
      </div>
    </div>
    <div class="p-4 bg-gray-50">
      <div class="flex items-center justify-between mb-3">
        <div>
          <h4 class="font-medium text-gray-900">会话超时时间</h4>
          <p class="text-sm text-gray-500">无操作自动登出时间</p>
        </div>
      </div>
      <div class="flex items-center gap-4">
        <select
          :value="sessionTimeout"
          @change="emit('update:sessionTimeout', Number(($event.target as HTMLSelectElement).value))"
          class="px-4 py-2 bg-white border border-gray-200 focus:outline-none focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500"
        >
          <option :value="15">15分钟</option>
          <option :value="30">30分钟</option>
          <option :value="60">1小时</option>
          <option :value="120">2小时</option>
        </select>
      </div>
    </div>
    <button @click="emit('changePassword')" class="w-full p-4 bg-gray-50 flex items-center justify-between hover:bg-gray-100 transition-colors">
      <div>
        <h4 class="font-medium text-gray-900">修改密码</h4>
        <p class="text-sm text-gray-500">定期更换密码以保证安全</p>
      </div>
      <ChevronRight class="w-5 h-5 text-gray-400" />
    </button>
  </div>
</template>