<script setup lang="ts">
import { ref, onMounted } from 'vue'
import { Bell, Check, CheckCheck, Trash2, ChevronLeft, ChevronRight, Info, AlertTriangle, CheckCircle, Settings } from 'lucide-vue-next'
import { API_BASE_URL, API_ENDPOINTS } from '@/config/api'

interface Notification {
  id: number
  uid: number
  title: string
  content: string
  type: 'info' | 'success' | 'warning' | 'system'
  is_read: 0 | 1
  created_at: string
  updated_at: string
}

const page = ref(1)
const pageSize = 20
const total = ref(0)
const unreadCount = ref(0)
const list = ref<Notification[]>([])
const loading = ref(false)
const filter = ref<string>('')

const typeLabels: Record<string, string> = {
  info: '通知',
  success: '成功',
  warning: '告警',
  system: '系统',
}

const typeColors: Record<string, string> = {
  info: 'bg-blue-100 text-blue-700',
  success: 'bg-green-100 text-green-700',
  warning: 'bg-yellow-100 text-yellow-700',
  system: 'bg-gray-200 text-gray-700',
}

const typeIcons: Record<string, any> = {
  info: Info,
  success: CheckCircle,
  warning: AlertTriangle,
  system: Settings,
}

const formatTime = (t: string) => {
  if (!t) return ''
  try {
    const d = new Date(t)
    return d.getFullYear() + '-' +
      String(d.getMonth() + 1).padStart(2, '0') + '-' +
      String(d.getDate()).padStart(2, '0') + ' ' +
      String(d.getHours()).padStart(2, '0') + ':' +
      String(d.getMinutes()).padStart(2, '0')
  } catch {
    return t
  }
}

const fetchList = async () => {
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return
  loading.value = true
  try {
    let url = `${API_BASE_URL}${API_ENDPOINTS.notification.list}?page=${page.value}&page_size=${pageSize}`
    if (filter.value !== '' && filter.value !== 'all') {
      if (filter.value === 'unread') {
        url += '&is_read=0'
      } else if (filter.value === 'read') {
        url += '&is_read=1'
      }
    }
    const res = await fetch(url, {
      method: 'GET',
      headers: { 'uid': uid, 'token': token },
    })
    const data = await res.json()
    if (data.code === 0 && data.data) {
      list.value = data.data.list || []
      total.value = data.data.total || 0
      unreadCount.value = data.data.unread || 0
    }
  } finally {
    loading.value = false
  }
}

const markRead = async (id: number) => {
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.notification.read}`, {
      method: 'POST',
      headers: {
        'uid': uid,
        'token': token,
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: `id=${id}`,
    })
    const data = await res.json()
    if (data.code === 0) {
      const item = list.value.find(n => n.id === id)
      if (item) item.is_read = 1
      unreadCount.value = Math.max(0, unreadCount.value - 1)
    }
  } catch {}
}

const markAllRead = async () => {
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.notification.readAll}`, {
      method: 'POST',
      headers: { 'uid': uid, 'token': token },
    })
    const data = await res.json()
    if (data.code === 0) {
      list.value.forEach(n => n.is_read = 1)
      unreadCount.value = 0
    }
  } catch {}
}

const removeOne = async (id: number) => {
  if (!confirm('确定要删除这条消息吗？')) return
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.notification.delete}`, {
      method: 'POST',
      headers: {
        'uid': uid,
        'token': token,
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: `id=${id}`,
    })
    const data = await res.json()
    if (data.code === 0) {
      const idx = list.value.findIndex(n => n.id === id)
      if (idx >= 0) {
        if (list.value[idx].is_read === 0) {
          unreadCount.value = Math.max(0, unreadCount.value - 1)
        }
        list.value.splice(idx, 1)
      }
      total.value = Math.max(0, total.value - 1)
    }
  } catch {}
}

const removeAll = async () => {
  if (!confirm('确定要清空全部消息吗？此操作不可恢复。')) return
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.notification.deleteAll}`, {
      method: 'POST',
      headers: { 'uid': uid, 'token': token },
    })
    const data = await res.json()
    if (data.code === 0) {
      list.value = []
      total.value = 0
      unreadCount.value = 0
    }
  } catch {}
}

const totalPages = () => Math.max(1, Math.ceil(total.value / pageSize))

const prevPage = () => {
  if (page.value > 1) {
    page.value--
    fetchList()
  }
}

const nextPage = () => {
  if (page.value < totalPages()) {
    page.value++
    fetchList()
  }
}

const changeFilter = (f: string) => {
  filter.value = f
  page.value = 1
  fetchList()
}

onMounted(() => {
  fetchList()
})
</script>

<template>
  <div class="p-6">
    <div class="mb-6">
      <h2 class="text-xl font-bold text-gray-900 mb-1">消息中心</h2>
      <p class="text-sm text-gray-500">查看并管理所有系统通知</p>
    </div>

    <div class="bg-white border border-gray-200 mb-4">
      <div class="flex items-center justify-between p-4 border-b border-gray-200">
        <div class="flex items-center gap-4">
          <div class="flex items-center gap-2 text-sm text-gray-700">
            <Bell class="w-4 h-4" />
            <span>未读：<span class="font-semibold text-orange-600">{{ unreadCount }}</span> 条</span>
          </div>
          <div class="text-sm text-gray-500">共 {{ total }} 条</div>
        </div>
        <div class="flex items-center gap-2">
          <div class="flex items-center gap-1 text-sm mr-2">
            <button
              @click="changeFilter('all')"
              :class="[
                'px-3 py-1 border transition-colors',
                filter === '' || filter === 'all'
                  ? 'bg-gray-900 text-white border-gray-900'
                  : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'
              ]"
            >全部</button>
            <button
              @click="changeFilter('unread')"
              :class="[
                'px-3 py-1 border transition-colors',
                filter === 'unread'
                  ? 'bg-gray-900 text-white border-gray-900'
                  : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'
              ]"
            >未读</button>
            <button
              @click="changeFilter('read')"
              :class="[
                'px-3 py-1 border transition-colors',
                filter === 'read'
                  ? 'bg-gray-900 text-white border-gray-900'
                  : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'
              ]"
            >已读</button>
          </div>
          <button
            @click="markAllRead"
            class="flex items-center gap-1 px-3 py-1.5 text-sm text-gray-700 border border-gray-300 bg-white hover:bg-gray-50 transition-colors"
          >
            <CheckCheck class="w-4 h-4" />
            全部已读
          </button>
          <button
            @click="removeAll"
            class="flex items-center gap-1 px-3 py-1.5 text-sm text-red-600 border border-red-300 bg-white hover:bg-red-50 transition-colors"
          >
            <Trash2 class="w-4 h-4" />
            清空全部
          </button>
        </div>
      </div>

      <div v-if="loading" class="p-12 text-center text-gray-400 text-sm">加载中...</div>
      <div v-else-if="list.length === 0" class="p-12 text-center">
        <Bell class="w-12 h-12 text-gray-300 mx-auto mb-3" />
        <p class="text-gray-500 text-sm">暂无消息</p>
      </div>
      <div v-else class="divide-y divide-gray-100">
        <div
          v-for="n in list"
          :key="n.id"
          :class="[
            'flex items-start gap-4 p-4 transition-colors hover:bg-gray-50',
            n.is_read === 0 ? 'bg-blue-50/30' : ''
          ]"
        >
          <div class="pt-1">
            <div :class="['w-8 h-8 flex items-center justify-center', typeColors[n.type] || typeColors.info]">
              <component :is="typeIcons[n.type] || Info" class="w-4 h-4" />
            </div>
          </div>
          <div class="flex-1 min-w-0">
            <div class="flex items-center gap-2 mb-1">
              <span v-if="n.is_read === 0" class="inline-block w-2 h-2 bg-red-500 rounded-full"></span>
              <span :class="[n.is_read === 0 ? 'font-semibold text-gray-900' : 'text-gray-700']" class="text-sm">
                {{ n.title }}
              </span>
              <span :class="['px-2 py-0.5 text-xs', typeColors[n.type] || typeColors.info]">
                {{ typeLabels[n.type] || '通知' }}
              </span>
              <span class="text-xs text-gray-400">{{ formatTime(n.created_at) }}</span>
            </div>
            <p class="text-sm text-gray-500 leading-relaxed">{{ n.content }}</p>
          </div>
          <div class="flex items-center gap-1 flex-shrink-0">
            <button
              v-if="n.is_read === 0"
              @click="markRead(n.id)"
              class="p-1.5 text-gray-500 hover:text-green-600 hover:bg-green-50 transition-colors"
              title="标记已读"
            >
              <Check class="w-4 h-4" />
            </button>
            <button
              @click="removeOne(n.id)"
              class="p-1.5 text-gray-500 hover:text-red-600 hover:bg-red-50 transition-colors"
              title="删除"
            >
              <Trash2 class="w-4 h-4" />
            </button>
          </div>
        </div>
      </div>

      <div v-if="total > pageSize" class="flex items-center justify-between p-4 border-t border-gray-200">
        <span class="text-sm text-gray-500">
          第 {{ (page - 1) * pageSize + 1 }} - {{ Math.min(page * pageSize, total) }} 条，共 {{ total }} 条
        </span>
        <div class="flex items-center gap-1">
          <button
            @click="prevPage"
            :disabled="page <= 1"
            :class="[
              'flex items-center gap-1 px-3 py-1.5 text-sm border transition-colors',
              page <= 1
                ? 'text-gray-300 border-gray-200 bg-gray-50 cursor-not-allowed'
                : 'text-gray-700 border-gray-300 bg-white hover:bg-gray-50'
            ]"
          >
            <ChevronLeft class="w-4 h-4" />上一页
          </button>
          <span class="px-3 py-1.5 text-sm text-gray-600">{{ page }} / {{ totalPages() }}</span>
          <button
            @click="nextPage"
            :disabled="page >= totalPages()"
            :class="[
              'flex items-center gap-1 px-3 py-1.5 text-sm border transition-colors',
              page >= totalPages()
                ? 'text-gray-300 border-gray-200 bg-gray-50 cursor-not-allowed'
                : 'text-gray-700 border-gray-300 bg-white hover:bg-gray-50'
            ]"
          >
            下一页<ChevronRight class="w-4 h-4" />
          </button>
        </div>
      </div>
    </div>
  </div>
</template>
