<script setup lang="ts">
import { ref, computed, onMounted, onUnmounted } from 'vue'
import { Building2, Server, Wifi, Cloud, Wrench, CheckCircle } from 'lucide-vue-next'
import SectionTitle from '@/components/SectionTitle.vue'
import { dataCenters, idcAdvantages, serviceSupport } from '@/data/idc'
import { animate, set } from 'animejs'

const selectedDc = ref('quanzhou-unicom')

const currentDc = computed(() => dataCenters.find(dc => dc.id === selectedDc.value)!)

const advantageIcons = [Server, Wifi, Cloud, Wrench]

const dcInfoLabels: Record<string, string> = {
  level: '机房级别',
  area: '机房面积',
  power: '电力设备',
  cooling: '空调设备',
  address: '机房地址',
}

const heroSection = ref<HTMLElement | null>(null)
const advantagesSection = ref<HTMLElement | null>(null)
const dataCentersSection = ref<HTMLElement | null>(null)
const serviceSupportSection = ref<HTMLElement | null>(null)

let heroObserver: IntersectionObserver | null = null
let advantagesObserver: IntersectionObserver | null = null
let dataCentersObserver: IntersectionObserver | null = null
let serviceSupportObserver: IntersectionObserver | null = null

const animateHero = () => {
  if (!heroSection.value) return
  
  const heroContent = heroSection.value.querySelector('.hero-content')
  
  if (heroContent) {
    set(heroContent as HTMLElement, {
      opacity: 0,
      translateY: 50
    })
    
    animate(heroContent as HTMLElement, {
      opacity: [0, 1],
      translateY: [50, 0],
      duration: 1000,
      easing: 'easeOutCubic'
    })
  }
}

const animateAdvantages = () => {
  if (!advantagesSection.value) return
  
  const advantageCards = advantagesSection.value.querySelectorAll('.advantage-card')
  
  advantageCards.forEach((card, index) => {
    set(card as HTMLElement, {
      opacity: 0,
      translateY: 40,
      translateX: index % 2 === 0 ? -30 : 30
    })
    
    animate(card as HTMLElement, {
      opacity: [0, 1],
      translateY: [40, 0],
      translateX: [index % 2 === 0 ? -30 : 30, 0],
      duration: 800,
      delay: index * 150,
      easing: 'easeOutBack'
    })
  })
}

const animateDataCenters = () => {
  if (!dataCentersSection.value) return
  
  const dcContent = dataCentersSection.value.querySelector('.dc-content')
  
  if (dcContent) {
    set(dcContent as HTMLElement, {
      opacity: 0,
      translateY: 30
    })
    
    animate(dcContent as HTMLElement, {
      opacity: [0, 1],
      translateY: [30, 0],
      duration: 900,
      easing: 'easeOutCubic'
    })
  }
}

const animateServiceSupport = () => {
  if (!serviceSupportSection.value) return
  
  const supportCards = serviceSupportSection.value.querySelectorAll('.support-card')
  
  supportCards.forEach((card, index) => {
    set(card as HTMLElement, {
      opacity: 0,
      translateY: 40,
      scale: 0.9
    })
    
    animate(card as HTMLElement, {
      opacity: [0, 1],
      translateY: [40, 0],
      scale: [0.9, 1],
      duration: 800,
      delay: index * 100,
      easing: 'easeOutBack'
    })
  })
}

onMounted(() => {
  heroObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          animateHero()
        }
      })
    },
    { threshold: 0.5 }
  )
  
  advantagesObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          animateAdvantages()
        }
      })
    },
    { threshold: 0.3 }
  )
  
  dataCentersObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          animateDataCenters()
        }
      })
    },
    { threshold: 0.3 }
  )
  
  serviceSupportObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          animateServiceSupport()
        }
      })
    },
    { threshold: 0.3 }
  )
  
  if (heroSection.value) {
    heroObserver.observe(heroSection.value)
  }
  
  if (advantagesSection.value) {
    advantagesObserver.observe(advantagesSection.value)
  }
  
  if (dataCentersSection.value) {
    dataCentersObserver.observe(dataCentersSection.value)
  }
  
  if (serviceSupportSection.value) {
    serviceSupportObserver.observe(serviceSupportSection.value)
  }
})

onUnmounted(() => {
  if (heroObserver && heroSection.value) {
    heroObserver.unobserve(heroSection.value)
  }
  if (advantagesObserver && advantagesSection.value) {
    advantagesObserver.unobserve(advantagesSection.value)
  }
  if (dataCentersObserver && dataCentersSection.value) {
    dataCentersObserver.unobserve(dataCentersSection.value)
  }
  if (serviceSupportObserver && serviceSupportSection.value) {
    serviceSupportObserver.unobserve(serviceSupportSection.value)
  }
})
</script>

<template>
  <div class="min-h-screen pt-12 lg:pt-14">
    <!-- Hero -->
    <section ref="heroSection" class="relative overflow-hidden">
      <div class="absolute inset-0">
        <img src="@/assets/images/banner-idc.7daeaddb.jpg" alt="IDC数据中心" class="w-full h-full object-cover" />
        <div class="absolute inset-0 bg-gradient-to-r from-black/50 via-black/30 to-transparent dark:from-dark-600/80 dark:via-dark-600/60"></div>
      </div>
      <div class="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16 lg:py-24">
        <div class="hero-content max-w-3xl">
          <div class="flex items-center gap-3 mb-6">
            <div class="w-12 h-12 rounded-lg bg-white/10 flex items-center justify-center">
              <Building2 class="w-6 h-6 text-flame-500" />
            </div>
            <h1 class="text-3xl lg:text-4xl font-bold text-white">IDC资源-数据中心</h1>
          </div>
          <p class="text-white/80 text-lg leading-relaxed">
            根据您的业务需求打造安全稳定的服务器运行环境，并根据您不断变化的业务需求提供针对性的解决方案，最大化实现您的业务价值。
          </p>
        </div>
      </div>
    </section>

    <!-- Advantages -->
    <section ref="advantagesSection" class="section-padding">
      <div class="max-w-7xl mx-auto">
        <SectionTitle title="机房优势" center />
        <div class="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div v-for="(adv, index) in idcAdvantages" :key="adv.title" class="advantage-card glass-card p-6">
            <div class="flex items-start gap-4">
              <div class="w-12 h-12 rounded-lg bg-flame-500/10 flex items-center justify-center shrink-0">
                <component :is="advantageIcons[index]" class="w-6 h-6 text-flame-500" />
              </div>
              <div class="flex-1">
                <h3 class="text-gray-900 dark:text-white font-semibold text-lg mb-1">{{ adv.title }}</h3>
                <p class="text-gray-400 dark:text-gray-500 text-xs mb-3">{{ adv.subtitle }}</p>
                <div class="space-y-2">
                  <div v-for="item in adv.items" :key="item.label" class="flex justify-between text-sm">
                    <span class="text-gray-400 dark:text-gray-500">{{ item.label }}</span>
                    <span class="text-gray-700 dark:text-gray-200 text-right max-w-[60%]">{{ item.value }}</span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>

    <!-- Data Centers -->
    <section ref="dataCentersSection" class="section-padding bg-gray-50 dark:bg-dark-500/30">
      <div class="max-w-7xl mx-auto">
        <SectionTitle title="机房资源" center />

        <div class="dc-content">
          <div class="flex flex-wrap justify-center gap-2 mb-8">
            <button
              v-for="dc in dataCenters"
              :key="dc.id"
              :class="[
                'px-4 py-2 rounded-lg text-sm font-medium transition-all duration-300',
                selectedDc === dc.id
                  ? 'bg-flame-gradient text-white shadow-lg shadow-flame-500/25'
                  : 'bg-gray-100 text-gray-500 hover:bg-gray-200 hover:text-gray-900 dark:bg-white/5 dark:text-gray-400 dark:hover:bg-white/10 dark:hover:text-white',
              ]"
              @click="selectedDc = dc.id"
            >
              {{ dc.shortName }}
            </button>
          </div>

          <div class="glass-card p-6 lg:p-8 max-w-4xl mx-auto">
            <h3 class="text-gray-900 dark:text-white font-semibold text-xl mb-6">{{ currentDc.name }}</h3>
            <div class="space-y-4">
              <div v-for="(label, key) in dcInfoLabels" :key="key" class="flex flex-col sm:flex-row gap-1 sm:gap-4">
                <span class="text-gray-400 dark:text-gray-500 text-sm shrink-0 w-20">{{ label }}</span>
                <span class="text-gray-700 dark:text-gray-200 text-sm">{{ currentDc[key as keyof typeof currentDc] }}</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>

    <!-- Service Support -->
    <section ref="serviceSupportSection" class="section-padding">
      <div class="max-w-7xl mx-auto">
        <SectionTitle title="服务支持" center />
        <div class="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          <div v-for="support in serviceSupport" :key="support.title" class="support-card glass-card p-6">
            <h3 class="text-gray-900 dark:text-white font-semibold text-lg mb-4">{{ support.title }}</h3>
            <ul class="space-y-2.5">
              <li v-for="item in support.items" :key="item" class="flex items-start gap-2 text-sm">
                <CheckCircle class="w-4 h-4 text-flame-500 shrink-0 mt-0.5" />
                <span class="text-gray-600 dark:text-gray-300">{{ item }}</span>
              </li>
            </ul>
          </div>
        </div>
      </div>
    </section>
  </div>
</template>