<script setup lang="ts">
import { ref, onMounted, onUnmounted } from 'vue'
import { Menu, X, Sun, Moon, Monitor, ChevronDown, X as XIcon, User, LayoutDashboard } from 'lucide-vue-next'
import { useTheme } from '@/composables/useTheme'
import { API_BASE_URL, API_ENDPOINTS } from '@/config/api'
import logoWhite from '@/assets/images/logo-w.svg'
import logoBlack from '@/assets/images/logo-b.svg'

const emit = defineEmits<{
  (e: 'loginSuccess'): void
}>()

const { theme, toggleTheme, isDark } = useTheme()
const scrolled = ref(false)
const mobileMenuOpen = ref(false)
const megaMenuOpen = ref<string | null>(null)
const megaMenuTimeout = ref<ReturnType<typeof setTimeout> | null>(null)
const contactModalOpen = ref(false)

const username = ref('')
const isLoggedIn = ref(false)

const fetchUserInfo = async () => {
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) {
    isLoggedIn.value = false
    return
  }

  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.user.info}`, {
      method: 'GET',
      headers: {
        'uid': uid,
        'token': token,
      },
    })
    const data = await res.json()
    if (data.code === -1) {
      localStorage.clear()
      isLoggedIn.value = false
      username.value = ''
      return
    }
    if (data.code === 0 && data.data) {
      username.value = data.data.name || data.data.username || data.data.phone || ''
      isLoggedIn.value = true
    }
  } catch {
    isLoggedIn.value = false
  }
}

const handleLogout = () => {
  localStorage.clear()
  isLoggedIn.value = false
  username.value = ''
  window.location.reload()
}

const refreshLoginState = () => {
  fetchUserInfo()
}

defineExpose({
  refreshLoginState,
})

onMounted(() => {
  fetchUserInfo()
})

const navLinks = [
  { name: '首页', path: '/', key: 'home', mega: false },
  { name: 'IDC资源', path: '/idc', key: 'idc', mega: true },
  { name: '云商品服务', path: '/cloudService/ecs', key: 'cloud', mega: true },
  { name: '解决方案', path: '/solution', key: 'solution', mega: true },
  { name: '关于我们', path: '/about', key: 'about', mega: false },
  { name: '加入火焰云', path: '/join', key: 'join', mega: false },
]

const megaMenuData: Record<string, {
  title: string
  description: string
  features: { name: string; desc: string; path: string }[]
}> = {
  cloud: {
    title: '云商品服务',
    description: '高性能、安全可靠的云计算产品与服务',
    features: [
      { name: '云服务器 ECS', desc: '安全可靠、秒级响应、弹性伸缩', path: '/cloudService/ecs' },
      { name: '对象存储 OSS', desc: '海量、安全、低成本云存储', path: '/cloudService/oss' },
      { name: '高防IP', desc: 'DDoS防护、WAF安全加速', path: '/cloudService/ecs' },
    ],
  },
  idc: {
    title: 'IDC 资源',
    description: '专业团队与丰富资源的数据中心服务',
    features: [
      { name: '服务器整柜托管', desc: '42U标准机柜，支持高电', path: '/idc' },
      { name: '互联网接入', desc: '电信、联通、移动、BGP', path: '/idc' },
      { name: '海内外云互联', desc: '多云互联、DCI互联', path: '/idc' },
      { name: '增值服务', desc: '机柜改造、运维服务', path: '/idc' },
    ],
  },
  solution: {
    title: '解决方案',
    description: '完备的行业解决方案，助力企业数字化转型',
    features: [
      { name: '教育行业', desc: '招生、教学、管理、测评端到端方案', path: '/solution/education' },
      { name: '电商行业', desc: '直播+电商一站式解决方案', path: '/solution/commerce' },
      { name: '游戏行业', desc: '云游戏敏捷转型方案', path: '/solution/game' },
      { name: '医疗行业', desc: '核心业务上云、数据标准化', path: '/solution/medical' },
      { name: '金融行业', desc: '金融云服务、安全合规解决方案', path: '/solution/financial' },
      { name: '旅游行业', desc: '智慧旅游、在线预订平台方案', path: '/solution/travel' },
    ],
  },
}

const handleScroll = () => {
  scrolled.value = window.scrollY > 20
}

const openMegaMenu = (key: string) => {
  if (megaMenuTimeout.value) {
    clearTimeout(megaMenuTimeout.value)
    megaMenuTimeout.value = null
  }
  megaMenuOpen.value = key
}

const closeMegaMenu = () => {
  megaMenuTimeout.value = setTimeout(() => {
    megaMenuOpen.value = null
  }, 200)
}

onMounted(() => {
  window.addEventListener('scroll', handleScroll)
})

onUnmounted(() => {
  window.removeEventListener('scroll', handleScroll)
  if (megaMenuTimeout.value) clearTimeout(megaMenuTimeout.value)
})
</script>

<template>
  <header
    :class="[
      'fixed top-0 left-0 right-0 z-50 transition-all duration-300',
      scrolled || megaMenuOpen
        ? 'bg-white/95 dark:bg-dark-600/95 backdrop-blur-md shadow-lg shadow-gray-200/50 dark:shadow-black/20'
        : 'bg-white/90 dark:bg-dark-700/50 backdrop-blur-md',
    ]"
  >
    <div class="w-full px-4 sm:px-6 lg:px-8">
      <div class="flex items-center justify-between h-12 lg:h-14">
        <router-link to="/" class="group flex-shrink-0">
          <img :src="isDark() ? logoBlack : logoWhite" alt="火焰云" class="h-6 w-auto group-hover:opacity-80 transition-opacity" />
        </router-link>

        <nav class="hidden lg:flex items-center gap-1 flex-1 ml-8">
          <div
            v-for="link in navLinks"
            :key="link.key"
            class="relative"
            @mouseenter="link.mega && openMegaMenu(link.key)"
            @mouseleave="link.mega && closeMegaMenu()"
          >
            <router-link
              :to="link.path"
              class="flex items-center gap-1 px-3 py-2 rounded-lg text-sm font-medium text-gray-700 hover:text-flame-500 dark:text-gray-200 dark:hover:text-flame-400 transition-colors"
              active-class="!text-flame-500"
            >
              {{ link.name }}
              <ChevronDown v-if="link.mega" class="w-3.5 h-3.5" />
            </router-link>
          </div>
        </nav>

        <div class="hidden lg:flex items-center gap-3">
          <div class="flex items-center gap-2">
            <button
              @click="toggleTheme"
              class="p-2 rounded-lg text-gray-600 hover:text-gray-900 dark:text-gray-300 dark:hover:text-white transition-colors"
              :title="theme === 'light' ? '切换到暗黑模式' : theme === 'dark' ? '跟随系统设置' : '切换到明亮模式'"
            >
              <Moon v-if="theme === 'dark'" class="w-5 h-5" />
              <Monitor v-else-if="theme === 'system'" class="w-5 h-5" />
              <Sun v-else class="w-5 h-5" />
            </button>
            <span class="text-xs text-gray-500 dark:text-gray-400 bg-gray-100 dark:bg-dark-700 px-2 py-1 rounded-full">
              {{ theme === 'light' ? '明亮' : theme === 'dark' ? '暗黑' : '系统' }}
            </span>
          </div>
          <router-link to="/doc" class="px-3 py-2 rounded-lg text-sm font-medium text-gray-700 hover:text-flame-500 dark:text-gray-200 dark:hover:text-flame-400 transition-colors">文档中心</router-link>
          <button
            @click="contactModalOpen = true"
            class="flame-btn-outline text-sm !px-4 !py-1.5 inline-flex items-center"
          >
            联系我们
          </button>
          <template v-if="isLoggedIn">
            <router-link
              to="/console/dashboard"
              class="flame-btn text-sm !px-4 !py-1.5 inline-flex items-center gap-2"
            >
              <LayoutDashboard class="w-4 h-4" />
              控制面板
            </router-link>
            <div class="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-gray-100 dark:bg-dark-700">
              <User class="w-4 h-4 text-gray-600 dark:text-gray-300" />
              <span class="text-sm font-medium text-gray-700 dark:text-gray-200">{{ username }}</span>
              <button
                @click="handleLogout"
                class="ml-1 text-xs text-gray-500 hover:text-flame-500 dark:text-gray-400 dark:hover:text-flame-400 transition-colors"
              >
                退出
              </button>
            </div>
          </template>
          <template v-else>
            <router-link to="/login" class="flame-btn-outline text-sm !px-4 !py-1.5 inline-flex items-center">登录</router-link>
            <router-link to="/register" class="flame-btn text-sm !px-4 !py-1.5 inline-flex items-center">注册</router-link>
          </template>
        </div>

        <button
          class="lg:hidden p-2 text-gray-700 dark:text-white"
          @click="mobileMenuOpen = !mobileMenuOpen"
        >
          <X v-if="mobileMenuOpen" class="w-6 h-6" />
          <Menu v-else class="w-6 h-6" />
        </button>
      </div>
    </div>

    <div
      v-if="mobileMenuOpen"
      class="lg:hidden bg-white dark:bg-dark-600 border-t border-gray-200 dark:border-white/10"
    >
      <div class="px-4 py-4 space-y-3">
        <router-link
          v-for="link in navLinks"
          :key="link.path"
          :to="link.path"
          class="block text-gray-700 dark:text-gray-200 hover:text-flame-500 transition-colors text-sm font-medium py-2"
          @click="mobileMenuOpen = false"
        >
          {{ link.name }}
        </router-link>
        <router-link
          to="/doc"
          class="block text-gray-700 dark:text-gray-200 hover:text-flame-500 transition-colors text-sm font-medium py-2"
          @click="mobileMenuOpen = false"
        >
          文档中心
        </router-link>
        <div class="flex gap-3 pt-2">
          <template v-if="isLoggedIn">
            <router-link
              to="/console/dashboard"
              class="flame-btn text-sm !px-4 !py-1.5 flex-1 text-center"
              @click="mobileMenuOpen = false"
            >
              控制面板
            </router-link>
            <button
              @click="handleLogout(); mobileMenuOpen = false"
              class="flame-btn-outline text-sm !px-4 !py-1.5 flex-1 text-center"
            >
              退出
            </button>
          </template>
          <template v-else>
            <router-link to="/login" class="flame-btn-outline text-sm !px-4 !py-1.5 flex-1 text-center" @click="mobileMenuOpen = false">登录</router-link>
            <router-link to="/register" class="flame-btn text-sm !px-4 !py-1.5 flex-1 text-center" @click="mobileMenuOpen = false">注册</router-link>
          </template>
        </div>
      </div>
    </div>
  </header>

  <!-- 联系我们弹窗 -->
  <Transition name="modal">
    <div v-if="contactModalOpen" class="fixed inset-0 z-50 flex items-center justify-center">
      <div class="absolute inset-0 bg-black/50 backdrop-blur-sm modal-backdrop" @click="contactModalOpen = false"></div>
      <div class="relative bg-white dark:bg-dark-600 rounded-xl shadow-2xl p-6 max-w-sm w-full mx-4 modal-content">
        <div class="flex items-center justify-between mb-6">
          <h3 class="text-xl font-bold text-gray-900 dark:text-white">联系我们</h3>
          <button
            @click="contactModalOpen = false"
            class="p-1.5 rounded-lg text-gray-400 hover:text-gray-600 dark:text-gray-500 dark:hover:text-gray-300 transition-colors"
          >
            <XIcon class="w-5 h-5" />
          </button>
        </div>
        <div class="flex flex-col items-center text-center space-y-4">
          <div class="relative group">
            <img src="@/assets/images/wechat2.jpg" alt="微信客服二维码" class="w-48 aspect-[3/4] object-contain rounded-lg border border-gray-200 dark:border-gray-700" />
          </div>
          <p class="text-gray-600 dark:text-gray-400 text-sm">扫码添加微信客服</p>
          <p class="text-gray-500 dark:text-gray-500 text-xs">工作时间: 7x24小时全天候服务</p>
        </div>
      </div>
    </div>
  </Transition>

    <Transition name="slide-down">
    <div
      v-if="megaMenuOpen"
      class="fixed top-12 lg:top-14 left-0 right-0 z-40 bg-white dark:bg-dark-500/95 backdrop-blur-md shadow-xl dark:shadow-2xl border-t border-gray-100 dark:border-white/10"
      @mouseenter="openMegaMenu(megaMenuOpen)"
      @mouseleave="closeMegaMenu()"
    >
      <div class="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
        <div v-if="megaMenuOpen && megaMenuData[megaMenuOpen]">
          <div class="flex items-start justify-between mb-6">
            <div>
              <h3 class="text-xl font-bold text-gray-900 dark:text-white">{{ megaMenuData[megaMenuOpen].title }}</h3>
              <p class="text-gray-500 dark:text-gray-400 mt-1">{{ megaMenuData[megaMenuOpen].description }}</p>
            </div>
            <router-link
              :to="navLinks.find(l => l.key === megaMenuOpen)?.path || '/'"
              class="text-sm text-flame-500 hover:text-flame-600 font-medium flex items-center gap-1"
            >
              查看全部 →
            </router-link>
          </div>
          <div class="grid grid-cols-2 md:grid-cols-4 gap-6">
            <router-link
              v-for="feature in megaMenuData[megaMenuOpen].features"
              :key="feature.name"
              :to="feature.path"
              class="group/item p-4 rounded-xl hover:bg-gray-50 dark:hover:bg-white/5 transition-all duration-300"
            >
              <h4 class="text-base font-semibold text-gray-900 dark:text-white mb-2 group-hover/item:text-flame-500 transition-colors">
                {{ feature.name }}
              </h4>
