<script setup lang="ts">
import { ref, computed, onMounted } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { Bell, User, ChevronDown, LayoutDashboard, Server, HardDrive, Activity, BarChart3, Users, FileText, Info, AlertTriangle, CheckCircle } from 'lucide-vue-next'
import logoBlack from '@/assets/images/logo-b.svg'
import { API_BASE_URL, API_ENDPOINTS } from '@/config/api'

const route = useRoute()
const router = useRouter()
const dropdownOpen = ref(false)
const showNotifications = ref(false)

const topMenus = [
  { key: 'dashboard', name: '控制台', path: '/console/dashboard', icon: LayoutDashboard },
  { key: 'ecs', name: '云服务器', path: '/console/ecs', icon: Server },
  { key: 'oss', name: '对象存储', path: '/console/oss', icon: HardDrive },
  { key: 'monitor', name: '监控告警', path: '/console/monitor', icon: Activity },
  { key: 'analytics', name: '数据分析', path: '/console/analytics', icon: BarChart3 },
  { key: 'users', name: 'AK管理', path: '/console/users', icon: Users },
  { key: 'logs', name: '操作日志', path: '/console/logs', icon: FileText },
]

const activeMenu = computed(() => {
  const path = route.path
  if (path.startsWith('/console/dashboard')) return 'dashboard'
  if (path.startsWith('/console/ecs')) return 'ecs'
  if (path.startsWith('/console/oss')) return 'oss'
  if (path.startsWith('/console/monitor')) return 'monitor'
  if (path.startsWith('/console/analytics')) return 'analytics'
  if (path.startsWith('/console/users')) return 'users'
  if (path.startsWith('/console/logs')) return 'logs'
  if (path.startsWith('/console/settings')) return 'settings'
  if (path.startsWith('/console/notification')) return 'dashboard'
  if (path.startsWith('/console/help')) return 'settings'
  return 'dashboard'
})

interface NotificationItem {
  id: number
  title: string
  content: string
  type: string
  is_read: number
  created_at: string
}

const unreadCount = ref(0)
const notifications = ref<NotificationItem[]>([])

const typeColors: Record<string, string> = {
  info: 'bg-blue-100 text-blue-600',
  success: 'bg-green-100 text-green-600',
  warning: 'bg-yellow-100 text-yellow-600',
  system: 'bg-gray-200 text-gray-600',
}

const typeIcons: Record<string, any> = {
  warning: AlertTriangle,
  success: CheckCircle,
  info: Info,
  system: Info,
}

const formatTime = (t: string) => {
  if (!t) return ''
  try {
    const d = new Date(t)
    const now = new Date()
    const diff = now.getTime() - d.getTime()
    const mins = Math.floor(diff / 60000)
    if (mins < 1) return '刚刚'
    if (mins < 60) return mins + '分钟前'
    const hours = Math.floor(mins / 60)
    if (hours < 24) return hours + '小时前'
    const days = Math.floor(hours / 24)
    if (days < 7) return days + '天前'
    return d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0') + '-' + String(d.getDate()).padStart(2, '0')
  } catch {
    return t
  }
}

const fetchNotifications = async () => {
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.notification.list}?page=1&page_size=5&is_read=0`, {
      method: 'GET',
      headers: { 'uid': uid, 'token': token },
    })
    const data = await res.json()
    if (data.code === 0 && data.data) {
      notifications.value = data.data.list || []
      unreadCount.value = data.data.unread || 0
    }
  } catch {
    // ignore
  }
}

const userName = ref('')

const fetchUserInfo = async () => {
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.user.info}`, {
      method: 'GET',
      headers: {
        'uid': uid,
        'token': token,
      },
    })
    const data = await res.json()
    if (data.code === -1) {
      localStorage.clear()
      return
    }
    if (data.code === 0 && data.data) {
      userName.value = data.data.name || data.data.username || data.data.phone || ''
    }
  } catch {
    // ignore
  }
}

onMounted(() => {
  fetchUserInfo()
  fetchNotifications()
})

const toggleDropdown = () => {
  dropdownOpen.value = !dropdownOpen.value
}

const logout = () => {
  localStorage.clear()
  window.location.href = '/login'
}

const goToSettings = () => {
  router.push('/console/settings')
}

const goToNotificationCenter = () => {
  router.push('/console/notification')
}
</script>

<template>
  <header style="height: 50px;" class="bg-[#202020] text-white border-b border-gray-800 flex items-center px-6 flex-shrink-0">
    <router-link to="/console/dashboard" class="flex items-center gap-2 mr-8 flex-shrink-0">
      <img :src="logoBlack" alt="火焰云" class="h-6 w-auto" />
    </router-link>
    <nav class="flex items-center gap-1 flex-1">
      <router-link
        v-for="menu in topMenus"
        :key="menu.key"
        :to="menu.path"
        :class="[
          'flex items-center gap-2 px-3 py-2 text-sm transition-colors',
          activeMenu === menu.key
            ? 'text-flame-500 border-b-2 border-flame-500'
            : 'text-gray-300 hover:text-white border-b-2 border-transparent'
        ]"
      >
        <component :is="menu.icon" class="w-4 h-4" />
        <span>{{ menu.name }}</span>
      </router-link>
    </nav>

    <div class="flex items-center gap-2">
      <div
        class="relative"
        @mouseenter="showNotifications = true"
        @mouseleave="showNotifications = false"
      >
        <button
          class="relative p-2 text-gray-300 hover:bg-gray-800 hover:text-white transition-colors"
        >
          <Bell class="w-5 h-5" />
          <span v-if="unreadCount > 0" class="absolute top-1 right-1 min-w-[16px] h-[16px] px-1 bg-red-500 text-white text-[10px] font-bold flex items-center justify-center">
            {{ unreadCount > 99 ? '99+' : unreadCount }}
          </span>
        </button>

        <Transition name="dropdown">
          <div
            v-if="showNotifications"
            class="absolute right-0 top-full mt-2 w-80 bg-white shadow-xl border border-gray-200 overflow-hidden z-50 text-gray-900"
          >
            <div class="px-4 py-3 border-b border-gray-100 flex items-center justify-between">
              <h3 class="font-semibold text-gray-900">通知中心</h3>
              <span v-if="unreadCount > 0" class="text-xs text-gray-500">未读 {{ unreadCount }} 条</span>
            </div>
            <ul v-if="notifications.length > 0" class="max-h-80 overflow-y-auto">
              <li
                v-for="notification in notifications"
                :key="notification.id"
                class="px-4 py-3 hover:bg-gray-50 cursor-pointer border-b border-gray-50 last:border-0"
              >
                <div class="flex items-start gap-3">
                  <div
                    :class="[
                      'w-8 h-8 flex items-center justify-center flex-shrink-0',
                      typeColors[notification.type] || typeColors.info
                    ]"
                  >
                    <component :is="typeIcons[notification.type] || Info" class="w-4 h-4" />
                  </div>
                  <div class="flex-1 min-w-0">
                    <h4 class="text-sm font-medium text-gray-900 truncate">{{ notification.title }}</h4>
                    <p v-if="notification.content" class="text-xs text-gray-500 mt-0.5 truncate">{{ notification.content }}</p>
                    <span class="text-xs text-gray-400">{{ formatTime(notification.created_at) }}</span>
                  </div>
                </div>
              </li>
            </ul>
            <div v-else class="py-8 text-center">
              <Bell class="w-8 h-8 text-gray-300 mx-auto mb-2" />
              <p class="text-sm text-gray-400">暂无未读消息</p>
            </div>
            <div class="px-4 py-2 bg-gray-50 border-t border-gray-100">
              <button
                @click="goToNotificationCenter"
                class="w-full text-sm text-flame-500 hover:text-flame-600 font-medium"
              >查看全部通知</button>
            </div>
          </div>
        </Transition>
      </div>

      <div class="h-6 w-px bg-gray-700"></div>

      <div
        class="relative"
        @mouseenter="dropdownOpen = true"
        @mouseleave="dropdownOpen = false"
      >
        <button
          class="flex items-center gap-2 px-3 py-1.5 hover:bg-gray-800 transition-colors"
        >
          <div class="w-8 h-8 bg-gradient-to-br from-flame-500 to-orange-500 flex items-center justify-center">
            <User class="w-4 h-4 text-white" />
          </div>
          <span class="text-sm font-medium text-white">{{ userName }}</span>
          <ChevronDown class="w-4 h-4 text-gray-300" />
        </button>

        <Transition name="dropdown">
          <div
            v-if="dropdownOpen"
            class="absolute right-0 top-full mt-2 w-48 bg-white shadow-xl border border-gray-200 overflow-hidden z-50 text-gray-900"
          >
            <div class="px-4 py-3 border-b border-gray-100">
              <p class="text-sm font-medium text-gray-900">{{ userName }}</p>
              <p class="text-xs text-gray-500 mt-0.5">个人账号</p>
            </div>
            <ul class="py-1">
              <li>
                <button
                  @click="goToSettings"
                  class="w-full px-4 py-2 text-sm text-gray-700 hover:bg-gray-50 transition-colors text-left"
                >
                  账号设置
                </button>
              </li>
              <li>
                <button @click="dropdownOpen = false; router.push('/console/settings/security')" class="w-full px-4 py-2 text-sm text-gray-700 hover:bg-gray-50 transition-colors text-left">
                  安全中心
                </button>
              </li>
              <li>
                <button @click="dropdownOpen = false; router.push('/console/help')" class="w-full px-4 py-2 text-sm text-gray-700 hover:bg-gray-50 transition-colors text-left">
                  帮助中心
                </button>
              </li>
              <li class="border-t border-gray-100 mt-1 pt-1">
                <button
                  @click="logout"
                  class="w-full px-4 py-2 text-sm text-red-500 hover:bg-red-50 transition-colors text-left"
                >
                  退出登录
                </button>
              </li>
            </ul>
          </div>
        </Transition>
      </div>
    </div>
  </header>
</template>

<style scoped>
.dropdown-enter-active,
.dropdown-leave-active {
  transition: all 0.2s ease;
}

.dropdown-enter-from,
.dropdown-leave-to {
  opacity: 0;
  transform: translateY(-10px);
}
</style>