const activeFaq = ref<string | null>(null)

const toggleFaq = (faqId: string) => {
  activeFaq.value = activeFaq.value === faqId ? null : faqId
}

const filteredFaqCategories = computed(() => {
  if (!searchQuery.value.trim()) {
    return faqCategories
  }
  const q = searchQuery.value.toLowerCase().trim()
  return faqCategories.map(category => {
    const filteredQuestions = category.questions.filter(question => 
      question.q.toLowerCase().includes(q) || question.a.toLowerCase().includes(q)
    )
    return { ...category, questions: filteredQuestions }
  }).filter(category => category.questions.length > 0)
})
