<script setup lang="ts">
import { ref, onMounted, onUnmounted } from 'vue'
import { Globe, Layers, Headphones, Cpu, BookOpen, BarChart4, Shield, Zap } from 'lucide-vue-next'
import SectionTitle from '@/components/SectionTitle.vue'
import ArchitectureDiagram from '@/components/ArchitectureDiagram.vue'
import idcEdu from '@/assets/images/idc-edu.jpg'
import { animate } from 'animejs'

const advantages = [
  { icon: Globe, title: '资源优势', desc: '全球多个数据中心、CDN节点，丰富的服务器、存储、网络带宽资源' },
  { icon: Layers, title: '生态优势', desc: '满足不同教育应用场景需求，提供端到端的整体解决方案' },
  { icon: Headphones, title: '服务优势', desc: '提供一对一、7x24小时的售前、交付、售后服务体验、提供个性化定制服务' },
  { icon: Cpu, title: '技术优势', desc: 'IaaS提供稳定、可靠、弹性、高并发支撑上层业务平稳运行' },
  { icon: BookOpen, title: '内容生态', desc: '整合优质教育资源，支持多格式教学内容分发，打造一站式知识平台' },
  { icon: BarChart4, title: '数据分析', desc: '实时采集学习行为数据，生成多维度学情报告，助力精准教学决策' },
  { icon: Shield, title: '安全合规', desc: '等保三级安全防护，严格遵循教育行业数据隐私规范，保护师生信息安全' },
  { icon: Zap, title: '极速响应', desc: '毫秒级低延迟传输，确保在线课堂流畅稳定，支持百万级并发访问' },
]

const layers = [
  {
    id: 'access',
    title: '接入层',
    badgeColor: 'access',
    cards: [
      { title: 'Web端访问' },
      { title: '移动端App' },
      { title: '小程序访问' },
      { title: '智能硬件接入' },
      { title: 'API网关' },
    ],
  },
  {
    id: 'business',
    title: '业务平台层',
    badgeColor: 'business',
    cards: [
      { title: '教学平台', desc: '课程/直播/点播' },
      { title: '学习平台', desc: '学习中心/作业/考试' },
      { title: '教务管理平台', desc: '用户/班级/教学管理' },
      { title: '运营与营销平台', desc: '招生/数据分析/CRM' },
      { title: '数据分析平台', desc: '学习效果/销售分析' },
    ],
  },
  {
    id: 'capability',
    title: '平台能力层 & 安全防护层',
    badgeColor: 'capability',
    capabilityCards: [
      { title: '音视频处理能力', desc: '视频转码/直播录制<br>媒体处理' },
      { title: '实时互动能力', desc: '实时通信(RTC)<br>即时通讯(IM)' },
      { title: '数据与AI能力', desc: '数据中台/智能推荐<br>智能评测/智能助教' },
      { title: '通用中间件', desc: '分布式缓存(Redis)<br>消息队列(MQ)/搜索引擎' },
    ],
    securityItems: [
      '网络安全 (DDoS/WAF)',
      '数据安全 (加密/脱敏)',
      '内容安全 (视频加密/水印)',
      '业务安全 (防作弊/账号安全)',
    ],
  },
  {
    id: 'infrastructure',
    title: '基础建设层',
    badgeColor: 'infrastructure',
    infrastructureItems: [
      '容器化部署(K8s)',
      '弹性计算(ECS)',
      'Serverless架构',
      '对象存储(OSS)',
      '文件存储(NAS)',
      '归档存储',
      '关系型数据库',
      'NoSQL数据库',
      '专有网络(VPC)',
      '负载均衡(SLB)',
      '云联网',
      'CDN内容分发',
      'API网关',
      '实时通信(RTC)',
    ],
  },
]

const heroSection = ref<HTMLElement | null>(null)
const advantagesSection = ref<HTMLElement | null>(null)
const architectureSection = ref<HTMLElement | null>(null)

const heroAnimated = ref(false)
const advantagesAnimated = ref(false)
const architectureAnimated = ref(false)

let heroObserver: IntersectionObserver | null = null
let advantagesObserver: IntersectionObserver | null = null
let architectureObserver: IntersectionObserver | null = null

const animateHero = () => {
  if (!heroSection.value || heroAnimated.value) return
  
  heroAnimated.value = true
  const heroContent = heroSection.value.querySelector('.hero-content')
  
  if (heroContent) {
    animate(heroContent as HTMLElement, {
      opacity: [0, 1],
      translateY: [50, 0],
      scale: [0.95, 1],
      duration: 1000,
      easing: 'easeOutCubic'
    })
  }
}

const animateAdvantages = () => {
  if (!advantagesSection.value || advantagesAnimated.value) return
  
  advantagesAnimated.value = true
  const advantageCards = advantagesSection.value.querySelectorAll('.advantage-card')
  
  advantageCards.forEach((card, index) => {
    animate(card as HTMLElement, {
      opacity: [0, 1],
      translateY: [40, 0],
      scale: [0.9, 1],
      duration: 800,
      delay: index * 100,
      easing: 'easeOutBack'
    })
  })
}

const animateArchitecture = () => {
  if (!architectureSection.value || architectureAnimated.value) return
  
  architectureAnimated.value = true
  const architectureContent = architectureSection.value.querySelector('.architecture-content')
  
  if (architectureContent) {
    animate(architectureContent as HTMLElement, {
      opacity: [0, 1],
      translateY: [30, 0],
      duration: 900,
      easing: 'easeOutCubic'
    })
  }
}

onMounted(() => {
  heroObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          animateHero()
        }
      })
    },
    { threshold: 0.5 }
  )
  
  advantagesObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          animateAdvantages()
        }
      })
    },
    { threshold: 0.3 }
  )
  
  architectureObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          animateArchitecture()
        }
      })
    },
    { threshold: 0.3 }
  )
  
  if (heroSection.value) {
    heroObserver.observe(heroSection.value)
  }
  
  if (advantagesSection.value) {
    advantagesObserver.observe(advantagesSection.value)
  }
  
  if (architectureSection.value) {
    architectureObserver.observe(architectureSection.value)
  }
})

onUnmounted(() => {
  if (heroObserver && heroSection.value) {
    heroObserver.unobserve(heroSection.value)
  }
  if (advantagesObserver && advantagesSection.value) {
    advantagesObserver.unobserve(advantagesSection.value)
  }
  if (architectureObserver && architectureSection.value) {
    architectureObserver.unobserve(architectureSection.value)
  }
})
</script>

<template>
  <div class="min-h-screen pt-12 lg:pt-14 flex flex-col">
    <section ref="heroSection" class="relative overflow-hidden">
      <div class="absolute inset-0">
        <img src="@/assets/images/education-bg.jpg" alt="教育行业" class="w-full h-full object-cover" />
        <div class="absolute inset-0 bg-gradient-to-r from-black/50 via-black/30 to-transparent"></div>
      </div>
      <div class="absolute top-1/3 right-1/4 w-80 h-80 bg-flame-500/10 rounded-full blur-3xl"></div>
      <div class="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16 lg:py-24">
        <div class="hero-content max-w-3xl backdrop-blur-md bg-white/20 dark:bg-black/20 p-8 rounded-xl">
          <h1 class="text-3xl lg:text-4xl font-bold text-white mb-4">在线教育解决方案</h1>
          <p class="text-white/80 text-lg leading-relaxed">对在线教育客户业务中遇到的招生、教学、管理、测评、审核及大数据提供端到端的解决方案。帮助各类教育客户快速搭建业务平台，降低人力成本，满足多场景下的功能需求。</p>
        </div>
      </div>
    </section>

    <section ref="advantagesSection" class="relative min-h-screen flex items-center py-36 lg:py-44 px-4 sm:px-6 lg:px-8">
      <div class="absolute inset-0 bg-cover bg-center" :style="{ backgroundImage: `url(${idcEdu})` }">
        <div class="absolute inset-0 backdrop-blur-xl bg-white/85 dark:bg-dark-800/80"></div>
      </div>
      <div class="relative max-w-7xl mx-auto w-full">
        <SectionTitle title="核心优势" center />
        <div class="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8 mt-16">
          <div v-for="adv in advantages" :key="adv.title" class="advantage-card glass-card p-8 text-center backdrop-blur-xl shadow-lg hover:shadow-xl transition-shadow">
            <div class="w-16 h-16 rounded-xl bg-flame-50 dark:bg-flame-500/20 flex items-center justify-center mx-auto mb-6">
              <component :is="adv.icon" class="w-8 h-8 text-flame-500" />
            </div>
            <h3 class="text-gray-900 dark:text-white font-bold text-xl mb-3">{{ adv.title }}</h3>
            <p class="text-gray-600 dark:text-gray-300 text-base leading-relaxed">{{ adv.desc }}</p>
          </div>
        </div>
      </div>
    </section>

    <section ref="architectureSection" class="py-24 px-4 sm:px-6 lg:px-8 bg-gray-50 dark:bg-gray-900">
      <div class="max-w-7xl mx-auto">
        <SectionTitle title="解决方案架构" center />
        <div class="architecture-content mt-12">
          <ArchitectureDiagram title="教育行业解决方案架构" :layers="layers" />
        </div>
      </div>
    </section>
  </div>
</template>