<script setup lang="ts">
import { ref, watch } from 'vue'
import { X, ChevronLeft, ChevronRight } from 'lucide-vue-next'
import { API_BASE_URL, API_ENDPOINTS } from '@/config/api'

interface LogItem {
  id: number
  ak_id: number
  action: string
  detail: string
  ip: string
  created_at: string
}

const props = defineProps<{
  show: boolean
  akId: number
  akName: string
}>()

const emit = defineEmits<{
  (e: 'close'): void
}>()

const logs = ref<LogItem[]>([])
const page = ref(1)
const loading = ref(false)

const getAuthHeaders = () => {
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return null
  return { uid, token }
}

const formatTime = (t: string) => {
  if (!t) return '-'
  return t.replace('T', ' ').substring(0, 19)
}

const fetchLogs = async (p: number = 1) => {
  const auth = getAuthHeaders()
  if (!auth) return
  page.value = p
  loading.value = true
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.accessKey.log}?ak_id=${props.akId}&page=${p}`, {
      headers: { 'uid': auth.uid, 'token': auth.token },
    })
    const data = await res.json()
    if (data.code === 0) {
      logs.value = data.data || []
    }
  } catch (e) {
    console.error('[fetchLogs]', e)
  } finally {
    loading.value = false
  }
}

const prevPage = () => {
  if (page.value > 1) {
    fetchLogs(page.value - 1)
  }
}

const nextPage = () => {
  fetchLogs(page.value + 1)
}

watch(() => props.show, (val) => {
  if (val) {
    fetchLogs(1)
  }
})
</script>

<template>
  <Teleport to="body">
    <div v-if="show" class="fixed inset-0 z-50 flex items-center justify-center">
      <div class="absolute inset-0 bg-black/40" @click="emit('close')"></div>
      <div class="relative bg-white rounded-xl shadow-2xl w-full max-w-2xl mx-4 p-6 max-h-[80vh] overflow-y-auto">
        <button @click="emit('close')" class="absolute top-4 right-4 text-gray-400 hover:text-gray-600"><X class="w-5 h-5" /></button>
        <h3 class="text-lg font-semibold text-gray-900 mb-1">操作日志 - {{ akName }}</h3>
        <p class="text-sm text-gray-500 mb-4">记录该 AK 的所有操作历史</p>

        <div v-if="loading" class="text-center py-8 text-gray-400">加载中...</div>
        <template v-else>
          <table class="w-full" v-if="logs.length > 0">
            <thead>
              <tr class="bg-gray-50 border-b border-gray-200">
                <th class="px-4 py-2 text-left text-xs font-medium text-gray-500">时间</th>
                <th class="px-4 py-2 text-left text-xs font-medium text-gray-500">操作</th>
                <th class="px-4 py-2 text-left text-xs font-medium text-gray-500">详情</th>
                <th class="px-4 py-2 text-left text-xs font-medium text-gray-500">IP</th>
              </tr>
            </thead>
            <tbody>
              <tr v-for="log in logs" :key="log.id" class="border-b border-gray-100">
                <td class="px-4 py-2 text-xs text-gray-500">{{ formatTime(log.created_at) }}</td>
                <td class="px-4 py-2 text-xs">
                  <span :class="['px-1.5 py-0.5 rounded text-xs', log.action === 'create' ? 'bg-green-100 text-green-700' : log.action === 'delete' ? 'bg-red-100 text-red-700' : 'bg-blue-100 text-blue-700']">
                    {{ log.action }}
                  </span>
                </td>
                <td class="px-4 py-2 text-xs text-gray-600">{{ log.detail }}</td>
                <td class="px-4 py-2 text-xs text-gray-400 font-mono">{{ log.ip }}</td>
              </tr>
            </tbody>
          </table>
          <div v-else class="text-center py-8 text-gray-400">暂无操作日志</div>

          <div class="flex items-center justify-center gap-4 mt-4">
            <button @click="prevPage" :disabled="page <= 1" class="px-3 py-1 text-sm text-gray-600 hover:bg-gray-100 disabled:opacity-30 disabled:cursor-not-allowed">
              <ChevronLeft class="w-4 h-4" />
            </button>
            <span class="text-sm text-gray-500">第 {{ page }} 页</span>
            <button @click="nextPage" :disabled="logs.length < 20" class="px-3 py-1 text-sm text-gray-600 hover:bg-gray-100 disabled:opacity-30 disabled:cursor-not-allowed">
              <ChevronRight class="w-4 h-4" />
            </button>
          </div>
        </template>
      </div>
    </div>
  </Teleport>
</template>