<script setup lang="ts">
import { ref, provide, computed } from 'vue'
import { useRoute } from 'vue-router'
import AppHeader from '@/components/AppHeader.vue'
import AppFooter from '@/components/AppFooter.vue'
import FloatingContact from '@/components/FloatingContact.vue'
import ConsoleLayout from '@/components/ConsoleLayout.vue'
import ToastContainer from '@/components/ToastContainer.vue'

const route = useRoute()

const appHeaderRef = ref<InstanceType<typeof AppHeader> | null>(null)

const refreshHeader = () => {
  appHeaderRef.value?.refreshLoginState()
}

provide('refreshHeader', refreshHeader)

const isConsoleRoute = computed(() => {
  return route.path.startsWith('/console/')
})
</script>

<template>
  <div v-if="isConsoleRoute" class="min-h-screen">
    <ConsoleLayout />
    <ToastContainer />
  </div>
  <div v-else class="min-h-screen flex flex-col overflow-x-hidden">
    <AppHeader ref="appHeaderRef" />
    <main class="flex-1">
      <router-view />
    </main>
    <AppFooter />
    <FloatingContact />
    <ToastContainer />
  </div>
</template>