import { ref } from 'vue'

export interface ToastItem {
  id: number
  message: string
  type: 'success' | 'error'
}

const toasts = ref<ToastItem[]>([])
let nextId = 1

export const toast = {
  success(msg: string) {
    const id = nextId++
    toasts.value.push({ id, message: msg, type: 'success' })
    setTimeout(() => {
      toasts.value = toasts.value.filter(t => t.id !== id)
    }, 2500)
  },
  error(msg: string) {
    const id = nextId++
    toasts.value.push({ id, message: msg, type: 'error' })
    setTimeout(() => {
      toasts.value = toasts.value.filter(t => t.id !== id)
    }, 2500)
  },
  get toasts() {
    return toasts
  },
}