<script setup lang="ts">
import { ref, watch } from 'vue'
import { X, Save } from 'lucide-vue-next'
import { API_BASE_URL, API_ENDPOINTS } from '@/config/api'
import { toast } from '@/composables/useToast'

interface Permission {
  id: number
  ak_id: number
  resource: string
  action: string
}

const props = defineProps<{
  show: boolean
  akId: number
  akName: string
}>()

const emit = defineEmits<{
  (e: 'close'): void
}>()

const resources = ['ecs', 'oss', 'monitor', 'analytics', 'billing']
const actions = ['read', 'write', 'admin']
const resourceLabels: Record<string, string> = {
  ecs: '云服务器', oss: '对象存储', monitor: '云监控', analytics: '数据分析', billing: '费用中心',
}
const actionLabels: Record<string, string> = {
  read: '只读', write: '读写', admin: '管理',
}

const permissionMap = ref<Record<string, boolean>>({})
const saving = ref(false)

const getAuthHeaders = () => {
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return null
  return { uid, token }
}

const fetchPermissions = async () => {
  const auth = getAuthHeaders()
  if (!auth) return
  permissionMap.value = {}
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.accessKey.permission}?ak_id=${props.akId}`, {
      headers: { 'uid': auth.uid, 'token': auth.token },
    })
    const data = await res.json()
    if (data.code === 0) {
      const perms: Permission[] = data.data || []
      for (const p of perms) {
        permissionMap.value[`${p.resource}_${p.action}`] = true
      }
    }
  } catch (e) {
    console.error('[fetchPermissions]', e)
  }
}

const save = async () => {
  const auth = getAuthHeaders()
  if (!auth) return
  saving.value = true
  const params = new URLSearchParams()
  params.append('ak_id', String(props.akId))
  for (const resource of resources) {
    for (const action of actions) {
      const key = `${resource}_${action}`
      params.append(key, permissionMap.value[key] ? '1' : '0')
    }
  }
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.accessKey.permission}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'uid': auth.uid, 'token': auth.token },
      body: params.toString(),
    })
    const data = await res.json()
    if (data.code === 0) {
      toast.success('权限保存成功')
      emit('close')
    } else {
      toast.error(data.echo || '保存失败')
    }
  } catch (e) {
    console.error('[save]', e)
    toast.error('保存失败')
  } finally {
    saving.value = false
  }
}

watch(() => props.show, (val) => {
  if (val) {
    fetchPermissions()
  }
})
</script>

<template>
  <Teleport to="body">
    <div v-if="show" class="fixed inset-0 z-50 flex items-center justify-center">
      <div class="absolute inset-0 bg-black/40" @click="emit('close')"></div>
      <div class="relative bg-white rounded-xl shadow-2xl w-full max-w-2xl mx-4 p-6 max-h-[80vh] overflow-y-auto">
        <button @click="emit('close')" class="absolute top-4 right-4 text-gray-400 hover:text-gray-600"><X class="w-5 h-5" /></button>
        <h3 class="text-lg font-semibold text-gray-900 mb-1">权限配置 - {{ akName }}</h3>
        <p class="text-sm text-gray-500 mb-4">为每个资源设置访问权限级别</p>

        <div class="border border-gray-200 rounded-lg overflow-hidden">
          <table class="w-full">
            <thead>
              <tr class="bg-gray-50 border-b border-gray-200">
                <th class="px-4 py-2 text-left text-xs font-medium text-gray-500">资源</th>
                <th class="px-4 py-2 text-center text-xs font-medium text-gray-500" v-for="a in actions" :key="a">{{ actionLabels[a] }}</th>
              </tr>
            </thead>
            <tbody>
              <tr v-for="r in resources" :key="r" class="border-b border-gray-100 hover:bg-gray-50">
                <td class="px-4 py-2 text-sm text-gray-900">{{ resourceLabels[r] }}</td>
                <td v-for="a in actions" :key="a" class="px-4 py-2 text-center">
                  <input
                    type="checkbox"
                    :checked="permissionMap[`${r}_${a}`] || false"
                    @change="(e: Event) => { const t = e.target as HTMLInputElement; permissionMap[`${r}_${a}`] = t.checked }"
                    class="w-4 h-4 text-flame-500 border-gray-300 rounded focus:ring-flame-500"
                  />
                </td>
              </tr>
            </tbody>
          </table>
        </div>

        <div class="mt-4 flex justify-end gap-3">
          <button @click="emit('close')" class="px-4 py-2 text-sm text-gray-700 bg-gray-100 hover:bg-gray-200">取消</button>
          <button @click="save" :disabled="saving" class="flame-btn flex items-center gap-2 px-4 py-2 text-sm">
            <Save class="w-4 h-4" />
            <span>{{ saving ? '保存中...' : '保存权限' }}</span>
          </button>
        </div>
      </div>
    </div>
  </Teleport>
</template>