<script setup lang="ts">
import { Key, Trash2, Shield, Clock } from 'lucide-vue-next'

interface AccessKey {
  id: number
  access_key: string
  name: string
  status: number
  remark: string
  created_at: string
  updated_at: string
}

defineProps<{
  aks: AccessKey[]
  loading: boolean
}>()

const emit = defineEmits<{
  (e: 'toggle', ak: AccessKey): void
  (e: 'permission', ak: AccessKey): void
  (e: 'log', ak: AccessKey): void
  (e: 'delete', ak: AccessKey): void
}>()

const formatTime = (t: string) => {
  if (!t) return '-'
  return t.replace('T', ' ').substring(0, 19)
}
</script>

<template>
  <div class="bg-white border border-gray-200">
    <table class="w-full" v-if="!loading">
      <thead>
        <tr class="border-b border-gray-200 bg-gray-50">
          <th class="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">AK 信息</th>
          <th class="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">状态</th>
          <th class="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">创建时间</th>
          <th class="px-4 py-3 text-right text-xs font-medium text-gray-500 uppercase">操作</th>
        </tr>
      </thead>
      <tbody>
        <tr v-if="aks.length === 0">
          <td colspan="4" class="px-4 py-12 text-center text-gray-400">暂无 AK，点击右上角「创建 AK」开始使用</td>
        </tr>
        <tr v-for="ak in aks" :key="ak.id" class="border-b border-gray-100 hover:bg-gray-50 transition-colors">
          <td class="px-4 py-3">
            <div class="flex items-center gap-2">
              <Key class="w-4 h-4 text-gray-400" />
              <div>
                <div class="text-sm font-medium text-gray-900">{{ ak.name || '未命名' }}</div>
                <div class="text-xs text-gray-600 font-mono">{{ ak.access_key }}</div>
              </div>
            </div>
          </td>
          <td class="px-4 py-3">
            <span :class="['inline-flex items-center gap-1 px-2 py-0.5 text-xs font-medium', ak.status === 1 ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-500']">
              <span :class="['w-1.5 h-1.5 rounded-full', ak.status === 1 ? 'bg-green-500' : 'bg-gray-400']"></span>
              {{ ak.status === 1 ? '启用' : '禁用' }}
            </span>
          </td>
          <td class="px-4 py-3 text-sm text-gray-500">{{ formatTime(ak.created_at) }}</td>
          <td class="px-4 py-3">
            <div class="flex items-center justify-end gap-2">
              <button @click="emit('toggle', ak)" :class="['px-2 py-1 text-xs', ak.status === 1 ? 'text-orange-600 hover:bg-orange-50' : 'text-green-600 hover:bg-green-50']">
                {{ ak.status === 1 ? '禁用' : '启用' }}
              </button>
              <button @click="emit('permission', ak)" class="px-2 py-1 text-xs text-blue-600 hover:bg-blue-50">
                <Shield class="w-3.5 h-3.5 inline mr-0.5" />权限
              </button>
              <button @click="emit('log', ak)" class="px-2 py-1 text-xs text-gray-600 hover:bg-gray-100">
                <Clock class="w-3.5 h-3.5 inline mr-0.5" />日志
              </button>
              <button @click="emit('delete', ak)" class="px-2 py-1 text-xs text-red-600 hover:bg-red-50">
                <Trash2 class="w-3.5 h-3.5" />
              </button>
            </div>
          </td>
        </tr>
      </tbody>
    </table>
    <div v-else class="px-4 py-12 text-center text-gray-400">加载中...</div>
  </div>
</template>