<script setup lang="ts">
import { ref } from 'vue'
import { API_BASE_URL, API_ENDPOINTS } from '@/config/api'
import { toast } from '@/composables/useToast'

defineProps<{
  show: boolean
}>()

const emit = defineEmits<{
  (e: 'close'): void
}>()

const passwordForm = ref({
  oldPassword: '',
  newPassword: '',
  confirmPassword: '',
})

const getAuthHeaders = () => {
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return null
  return { uid, token }
}

const changePassword = async () => {
  const auth = getAuthHeaders()
  if (!auth) {
    toast.error('请先登录')
    return
  }

  if (passwordForm.value.newPassword.length < 6) {
    toast.error('新密码至少6位')
    return
  }

  if (passwordForm.value.newPassword !== passwordForm.value.confirmPassword) {
    toast.error('两次新密码输入不一致')
    return
  }

  const params = new URLSearchParams()
  params.append('old_password', passwordForm.value.oldPassword)
  params.append('new_password', passwordForm.value.newPassword)

  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.password.change}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'uid': auth.uid,
        'token': auth.token,
      },
      body: params.toString(),
    })
    const data = await res.json()
    if (data.code === 0) {
      toast.success('密码修改成功')
      passwordForm.value = { oldPassword: '', newPassword: '', confirmPassword: '' }
      emit('close')
    } else {
      toast.error(data.echo || '密码修改失败')
    }
  } catch (e) {
    console.error('[changePassword] 异常', e)
    toast.error('密码修改失败')
  }
}

const close = () => {
  passwordForm.value = { oldPassword: '', newPassword: '', confirmPassword: '' }
  emit('close')
}
</script>

<template>
  <Teleport to="body">
    <div v-if="show" class="fixed inset-0 z-50 flex items-center justify-center">
      <div class="absolute inset-0 bg-black/40" @click="close"></div>
      <div class="relative bg-white rounded-xl shadow-2xl w-full max-w-md mx-4 p-6">
        <h3 class="text-lg font-semibold text-gray-900 mb-4">修改密码</h3>
        <div class="space-y-4">
          <div>
            <label class="block text-sm font-medium text-gray-700 mb-1">原密码</label>
            <input
              v-model="passwordForm.oldPassword"
              type="password"
              class="w-full px-4 py-3 bg-white border border-gray-300 focus:outline-none focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500"
              placeholder="请输入原密码"
            />
          </div>
          <div>
            <label class="block text-sm font-medium text-gray-700 mb-1">新密码</label>
            <input
              v-model="passwordForm.newPassword"
              type="password"
              class="w-full px-4 py-3 bg-white border border-gray-300 focus:outline-none focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500"
              placeholder="请输入新密码（至少6位）"
            />
          </div>
          <div>
            <label class="block text-sm font-medium text-gray-700 mb-1">确认新密码</label>
            <input
              v-model="passwordForm.confirmPassword"
              type="password"
              class="w-full px-4 py-3 bg-white border border-gray-300 focus:outline-none focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500"
              placeholder="请再次输入新密码"
            />
          </div>
        </div>
        <div class="mt-6 flex justify-end gap-3">
          <button @click="close" class="px-4 py-2 text-sm font-medium text-gray-700 bg-gray-100 hover:bg-gray-200 transition-colors">取消</button>
          <button @click="changePassword" class="flame-btn px-4 py-2 text-sm font-medium">确认修改</button>
        </div>
      </div>
    </div>
  </Teleport>
</template>