<script setup lang="ts">
import { ref, onMounted } from 'vue'
import { Server, HardDrive,
  Activity, Clock,
  AlertTriangle, CheckCircle, Info
} from 'lucide-vue-next'
import { animate } from 'animejs'
import { API_BASE_URL, API_ENDPOINTS } from '@/config/api'

const lastLoginTime = ref('')
const displayName = ref('')

const formatDateTime = (s: string) => {
  if (!s) return ''
  try {
    const raw = s.replace('T', ' ').slice(0, 19)
    const d = new Date(raw.replace(/-/g, '/'))
    if (isNaN(d.getTime())) return s
    const now = new Date()
    const isToday = d.getFullYear() === now.getFullYear() &&
      d.getMonth() === now.getMonth() &&
      d.getDate() === now.getDate()
    const hh = String(d.getHours()).padStart(2, '0')
    const mm = String(d.getMinutes()).padStart(2, '0')
    if (isToday) {
      return '今天 ' + hh + ':' + mm
    }
    return (d.getFullYear() + '-' +
      String(d.getMonth() + 1).padStart(2, '0') + '-' +
      String(d.getDate()).padStart(2, '0') +
      ' ' + hh + ':' + mm)
  } catch {
    return s
  }
}

const fetchUserInfo = async () => {
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return
  try {
    const res = await fetch(API_BASE_URL + API_ENDPOINTS.user.info, {
      method: 'GET',
      headers: { uid, token },
    })
    const data = await res.json()
    if (data.code === 0 && data.data) {
      displayName.value = data.data.name || data.data.username || ''
      lastLoginTime.value = formatDateTime(data.data.last_login_time || '')
    }
  } catch {
    // ignore
  }
}

const stats = ref([
  { 
    title: '云服务器', 
    value: '24', 
    unit: '台', 
    icon: Server, 
    bgColor: 'bg-blue-50',
    iconColor: 'text-blue-500',
    borderColor: 'border-blue-100'
  },
  { 
    title: '存储空间', 
    value: '12.8', 
    unit: 'TB', 
    icon: HardDrive, 
    bgColor: 'bg-green-50',
    iconColor: 'text-green-500',
    borderColor: 'border-green-100'
  },
  ])

const recentActivities = ref([
  { id: 1, type: 'success', title: 'ECS实例启动成功', resource: 'ecs-flame-001', time: '2分钟前' },
  { id: 2, type: 'info', title: '存储快照创建完成', resource: 'oss-bucket-002', time: '15分钟前' },
  { id: 3, type: 'warning', title: 'CPU使用率过高预警', resource: 'ecs-flame-003', time: '30分钟前' },
  { id: 4, type: 'info', title: 'SSL证书即将过期', resource: 'cert-flame-001', time: '2小时前' },
])

const serviceStatus = ref([
  { name: '云服务器 ECS', status: 'normal', region: '华北-北京' },
  { name: '对象存储 OSS', status: 'normal', region: '华东-上海' },
  { name: '数据库服务', status: 'warning', region: '西南-成都' },
])

const getStatusIcon = (status: string) => {
  switch (status) {
    case 'normal':
      return CheckCircle
    case 'warning':
      return AlertTriangle
    default:
      return Info
  }
}

const getStatusColor = (status: string) => {
  switch (status) {
    case 'normal':
      return 'text-green-500 bg-green-100'
    case 'warning':
      return 'text-yellow-500 bg-yellow-100'
    default:
      return 'text-blue-500 bg-blue-100'
  }
}

const getStatusText = (status: string) => {
  switch (status) {
    case 'normal':
      return '运行正常'
    case 'warning':
      return '部分异常'
    default:
      return '维护中'
  }
}

onMounted(() => {
  fetchUserInfo()

  animate('.stat-card', {
    translateY: [30, 0],
    opacity: [0, 1],
    duration: 600,
    easing: 'easeOutQuad',
    delay: (el: HTMLElement, i: number) => i * 100
  })

  animate('.section-title', {
    translateX: [-20, 0],
    opacity: [0, 1],
    duration: 500,
    easing: 'easeOutQuad',
    delay: 400
  })

  animate('.activity-item', {
    translateX: [-20, 0],
    opacity: [0, 1],
    duration: 400,
    easing: 'easeOutQuad',
    delay: (el: HTMLElement, i: number) => 500 + i * 80
  })
})
</script>

<template>
  <div class="p-6 space-y-6">
    <div class="flex items-center justify-between">
      <div>
        <h1 class="text-2xl font-bold text-gray-900">{{ displayName ? displayName + '，' : '' }}控制台首页</h1>
        <p class="text-gray-500 mt-1">欢迎回来，这是您的资源概览</p>
      </div>
      <div v-if="lastLoginTime" class="flex items-center gap-2 px-3 py-1.5 bg-blue-50">
        <Clock class="w-4 h-4 text-blue-500" />
        <span class="text-sm text-blue-600">上次登录: {{ lastLoginTime }}</span>
      </div>
    </div>

    <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
      <div
        v-for="(stat, index) in stats"
        :key="index"
        class="stat-card bg-white border transition-all duration-300 hover:shadow-lg hover:-translate-y-0.5"
        :class="stat.borderColor"
      >
        <div class="p-6">
          <div class="flex items-start justify-between">
            <div :class="['w-12 h-12 flex items-center justify-center', stat.bgColor]">
              <component :is="stat.icon" :class="['w-6 h-6', stat.iconColor]" />
            </div>
          </div>
          <div class="mt-4">
            <p class="text-sm text-gray-500">{{ stat.title }}</p>
            <div class="flex items-baseline gap-1 mt-1">
              <span class="text-3xl font-bold text-gray-900">{{ stat.value }}</span>
              <span class="text-sm text-gray-500">{{ stat.unit }}</span>
            </div>
          </div>
        </div>
      </div>
    </div>

    <div class="grid grid-cols-1 lg:grid-cols-3 gap-6">
      <div class="lg:col-span-2 bg-white border border-gray-100 overflow-hidden">
        <div class="section-title px-6 py-4 border-b border-gray-100">
          <h2 class="text-lg font-semibold text-gray-900">最近活动</h2>
        </div>
        <div class="divide-y divide-gray-50">
          <div
            v-for="activity in recentActivities"
            :key="activity.id"
            class="activity-item px-6 py-4 hover:bg-gray-50 transition-colors cursor-pointer"
          >
            <div class="flex items-center gap-4">
              <div
                :class="[
                  'w-10 h-10 flex items-center justify-center',
                  activity.type === 'success' ? 'bg-green-50' :
                  activity.type === 'warning' ? 'bg-yellow-50' : 'bg-blue-50'
                ]"
              >
                <CheckCircle v-if="activity.type === 'success'" class="w-5 h-5 text-green-500" />
                <AlertTriangle v-else-if="activity.type === 'warning'" class="w-5 h-5 text-yellow-500" />
                <Info v-else class="w-5 h-5 text-blue-500" />
              </div>
              <div class="flex-1 min-w-0">
                <p class="text-sm font-medium text-gray-900 truncate">{{ activity.title }}</p>
                <p class="text-xs text-gray-500 mt-0.5">{{ activity.resource }}</p>
              </div>
              <span class="text-xs text-gray-400 whitespace-nowrap">{{ activity.time }}</span>
            </div>
          </div>
        </div>
        <div class="px-6 py-3 bg-gray-50 border-t border-gray-100">
          <button class="w-full text-sm text-flame-500 hover:text-flame-600 font-medium">查看全部活动</button>
        </div>
      </div>

      <div class="bg-white border border-gray-100 overflow-hidden">
        <div class="section-title px-6 py-4 border-b border-gray-100">
          <h2 class="text-lg font-semibold text-gray-900">服务状态</h2>
        </div>
        <div class="divide-y divide-gray-50">
          <div
            v-for="service in serviceStatus"
            :key="service.name"
            class="px-6 py-4 hover:bg-gray-50 transition-colors"
          >
            <div class="flex items-center justify-between">
              <div>
                <p class="text-sm font-medium text-gray-900">{{ service.name }}</p>
                <p class="text-xs text-gray-500 mt-0.5">{{ service.region }}</p>
              </div>
              <div class="flex items-center gap-2">
                <div :class="['w-2 h-2', service.status === 'normal' ? 'bg-green-500' : 'bg-yellow-500']"></div>
                <span class="text-xs text-gray-500">{{ getStatusText(service.status) }}</span>
              </div>
            </div>
          </div>
        </div>
        <div class="px-6 py-3 bg-gray-50 border-t border-gray-100">
          <button class="w-full text-sm text-flame-500 hover:text-flame-600 font-medium">查看详细状态</button>
        </div>
      </div>
    </div>
  </div>
</template>