<script setup lang="ts">
import { ref, computed, onMounted, watch } from 'vue'
import { useRoute } from 'vue-router'
import { Save } from 'lucide-vue-next'
import { API_BASE_URL, API_ENDPOINTS } from '@/config/api'
import { toast } from '@/composables/useToast'
import ProfileTab from './SettingsPage/ProfileTab.vue'
import SecurityTab from './SettingsPage/SecurityTab.vue'
import NotificationTab from './SettingsPage/NotificationTab.vue'
import PasswordModal from './SettingsPage/PasswordModal.vue'

const route = useRoute()

const activeTab = computed(() => {
  const path = route.path
  if (path.includes('/security')) return 'security'
  if (path.includes('/notification')) return 'notification'
  return 'profile'
})

const tabTitles: Record<string, string> = {
  profile: '个人信息',
  security: '安全设置',
  notification: '通知设置',
}

const profileForm = ref({
  name: '',
  company: '',
  department: '',
  phone: '',
  email: '',
  avatar: '',
})

const profileLoading = ref(false)
const profileError = ref('')

const securitySettings = ref({
  twoFactor: true,
  loginAlert: true,
  sessionTimeout: 30,
})

const notificationSettings = ref({
  email: true,
  sms: false,
})

const showPasswordModal = ref(false)

const getAuthHeaders = () => {
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return null
  return { uid, token }
}

const fetchProfile = async () => {
  const auth = getAuthHeaders()
  if (!auth) {
    profileError.value = '请先登录后查看个人信息'
    return
  }
  profileLoading.value = true
  profileError.value = ''
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.user.info}`, {
      method: 'GET',
      headers: { 'uid': auth.uid, 'token': auth.token },
    })
    const data = await res.json()
    if (data.code === 0 && data.data) {
      profileForm.value.name = data.data.name || ''
      profileForm.value.company = data.data.company || ''
      profileForm.value.department = data.data.department || ''
      profileForm.value.phone = data.data.phone || ''
      profileForm.value.email = data.data.email || ''
      profileForm.value.avatar = data.data.avatar || ''
    } else {
      profileError.value = data.echo || '加载失败'
    }
  } catch (e) {
    console.error('[fetchProfile] 异常', e)
    profileError.value = '网络请求失败，请检查后端服务是否启动'
  } finally {
    profileLoading.value = false
  }
}

const saveProfile = async () => {
  const auth = getAuthHeaders()
  if (!auth) {
    toast.error('请先登录')
    return
  }
  const params = new URLSearchParams()
  params.append('name', profileForm.value.name)
  params.append('company', profileForm.value.company)
  params.append('department', profileForm.value.department)
  params.append('phone', profileForm.value.phone)
  params.append('email', profileForm.value.email)
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.user.info}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'uid': auth.uid,
        'token': auth.token,
      },
      body: params.toString(),
    })
    const data = await res.json()
    if (data.code === 0) {
      toast.success('保存成功')
    } else {
      toast.error(data.echo || '保存失败')
    }
  } catch (e) {
    console.error('[saveProfile] 异常', e)
    toast.error('保存失败')
  }
}

const fetchSecurity = async () => {
  const auth = getAuthHeaders()
  if (!auth) return
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.security.info}`, {
      method: 'GET',
      headers: { 'uid': auth.uid, 'token': auth.token },
    })
    const data = await res.json()
    if (data.code === 0 && data.data) {
      securitySettings.value.twoFactor = data.data.two_factor === 1 || data.data.two_factor === '1'
      securitySettings.value.loginAlert = data.data.login_alert === 1 || data.data.login_alert === '1'
      securitySettings.value.sessionTimeout = Number(data.data.session_timeout) || 30
    }
  } catch (e) {
    console.error('[fetchSecurity] 异常', e)
  }
}

const saveSecurity = async () => {
  const auth = getAuthHeaders()
  if (!auth) {
    toast.error('请先登录')
    return
  }
  const params = new URLSearchParams()
  params.append('two_factor', securitySettings.value.twoFactor ? '1' : '0')
  params.append('login_alert', securitySettings.value.loginAlert ? '1' : '0')
  params.append('session_timeout', String(securitySettings.value.sessionTimeout))
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.security.info}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'uid': auth.uid,
        'token': auth.token,
      },
      body: params.toString(),
    })
    const data = await res.json()
    if (data.code === 0) {
      toast.success('保存成功')
    } else {
      toast.error(data.echo || '保存失败')
    }
  } catch (e) {
    console.error('[saveSecurity] 异常', e)
    toast.error('保存失败')
  }
}

const fetchNotification = async () => {
  const auth = getAuthHeaders()
  if (!auth) return
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.notificationSetting.info}`, {
      method: 'GET',
      headers: { 'uid': auth.uid, 'token': auth.token },
    })
    const data = await res.json()
    if (data.code === 0 && data.data) {
      notificationSettings.value.email = data.data.email === 1 || data.data.email === '1'
      notificationSettings.value.sms = data.data.sms === 1 || data.data.sms === '1'
    }
  } catch (e) {
    console.error('[fetchNotification] 异常', e)
  }
}

const saveNotification = async () => {
  const auth = getAuthHeaders()
  if (!auth) {
    toast.error('请先登录')
    return
  }
  const params = new URLSearchParams()
  params.append('email', notificationSettings.value.email ? '1' : '0')
  params.append('sms', notificationSettings.value.sms ? '1' : '0')
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.notificationSetting.info}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'uid': auth.uid,
        'token': auth.token,
      },
      body: params.toString(),
    })
    const data = await res.json()
    if (data.code === 0) {
      toast.success('保存成功')
    } else {
      toast.error(data.echo || '保存失败')
    }
  } catch (e) {
    console.error('[saveNotification] 异常', e)
    toast.error('保存失败')
  }
}

const saveCurrentTab = () => {
  switch (activeTab.value) {
    case 'profile': saveProfile(); break
    case 'security': saveSecurity(); break
    case 'notification': saveNotification(); break
  }
}

const fetchCurrentTab = () => {
  switch (activeTab.value) {
    case 'profile': fetchProfile(); break
    case 'security': fetchSecurity(); break
    case 'notification': fetchNotification(); break
  }
}

onMounted(() => {
  fetchCurrentTab()
})

watch(() => route.path, () => {
  fetchCurrentTab()
})
</script>

<template>
  <div>
    <div class="bg-white border-b border-gray-100 px-6 py-5">
      <h1 class="text-2xl font-bold text-gray-900">{{ tabTitles[activeTab] }}</h1>
      <p v-if="activeTab === 'profile'" class="text-gray-500 mt-1">管理您的账号信息</p>
      <p v-else-if="activeTab === 'security'" class="text-gray-500 mt-1">配置账号安全选项</p>
      <p v-else-if="activeTab === 'notification'" class="text-gray-500 mt-1">管理您的通知偏好</p>
    </div>

    <div class="p-6 space-y-6">
      <div class="bg-white border border-gray-100 overflow-hidden">
        <div class="p-6">
          <ProfileTab
            v-if="activeTab === 'profile'"
            :name="profileForm.name"
            :company="profileForm.company"
            :department="profileForm.department"
            :phone="profileForm.phone"
            :email="profileForm.email"
            :avatar="profileForm.avatar"
            :loading="profileLoading"
            :error="profileError"
            @update:name="profileForm.name = $event"
            @update:company="profileForm.company = $event"
            @update:department="profileForm.department = $event"
            @update:phone="profileForm.phone = $event"
            @update:email="profileForm.email = $event"
            @update:avatar="profileForm.avatar = $event"
          />

          <SecurityTab
            v-else-if="activeTab === 'security'"
            :two-factor="securitySettings.twoFactor"
            :login-alert="securitySettings.loginAlert"
            :session-timeout="securitySettings.sessionTimeout"
            @update:two-factor="securitySettings.twoFactor = $event"
            @update:login-alert="securitySettings.loginAlert = $event"
            @update:session-timeout="securitySettings.sessionTimeout = $event"
            @change-password="showPasswordModal = true"
          />

          <NotificationTab
            v-else-if="activeTab === 'notification'"
            :email="notificationSettings.email"
            :sms="notificationSettings.sms"
            @update:email="notificationSettings.email = $event"
            @update:sms="notificationSettings.sms = $event"
          />

          <div class="mt-8 flex justify-end">
            <button @click="saveCurrentTab" class="flame-btn flex items-center gap-2">
              <Save class="w-4 h-4" />
              <span class="text-sm font-medium">保存设置</span>
            </button>
          </div>
        </div>
      </div>
    </div>

    <PasswordModal
      :show="showPasswordModal"
      @close="showPasswordModal = false"
    />
  </div>
</template>