<script setup lang="ts">
import { ref, onMounted } from 'vue'
import { Plus } from 'lucide-vue-next'
import { API_BASE_URL, API_ENDPOINTS } from '@/config/api'
import { toast } from '@/composables/useToast'
import AkTable from './UserPage/AkTable.vue'
import CreateAkModal from './UserPage/CreateAkModal.vue'
import PermissionModal from './UserPage/PermissionModal.vue'
import LogModal from './UserPage/LogModal.vue'
import ConfirmModal from './UserPage/ConfirmModal.vue'

interface AccessKey {
  id: number
  access_key: string
  name: string
  status: number
  remark: string
  created_at: string
  updated_at: string
}

const aks = ref<AccessKey[]>([])
const loading = ref(false)

const showCreateModal = ref(false)
const showPermissionModal = ref(false)
const permissionAkId = ref(0)
const permissionAkName = ref('')
const showLogModal = ref(false)
const logAkId = ref(0)
const logAkName = ref('')
const showConfirmModal = ref(false)
const confirmTarget = ref<AccessKey | null>(null)

const getAuthHeaders = () => {
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return null
  return { uid, token }
}

const fetchAks = async () => {
  const auth = getAuthHeaders()
  if (!auth) return
  loading.value = true
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.accessKey.list}`, {
      headers: { 'uid': auth.uid, 'token': auth.token },
    })
    const data = await res.json()
    if (data.code === 0) {
      aks.value = data.data || []
    }
  } catch (e) {
    console.error('[fetchAks]', e)
  } finally {
    loading.value = false
  }
}

const toggleStatus = async (ak: AccessKey) => {
  const auth = getAuthHeaders()
  if (!auth) return
  const newStatus = ak.status === 1 ? 0 : 1
  const params = new URLSearchParams()
  params.append('action', 'update')
  params.append('id', String(ak.id))
  params.append('status', String(newStatus))
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.accessKey.list}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'uid': auth.uid, 'token': auth.token },
      body: params.toString(),
    })
    const data = await res.json()
    if (data.code === 0) {
      ak.status = newStatus
      toast.success(newStatus === 1 ? '已启用' : '已禁用')
    } else {
      toast.error(data.echo || '操作失败')
    }
  } catch (e) {
    console.error('[toggleStatus]', e)
    toast.error('操作失败')
  }
}

const deleteAk = (ak: AccessKey) => {
  confirmTarget.value = ak
  showConfirmModal.value = true
}

const confirmDeleteAk = async () => {
  const ak = confirmTarget.value
  if (!ak) return
  showConfirmModal.value = false
  confirmTarget.value = null
  const auth = getAuthHeaders()
  if (!auth) return
  const params = new URLSearchParams()
  params.append('action', 'delete')
  params.append('id', String(ak.id))
  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.accessKey.list}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'uid': auth.uid, 'token': auth.token },
      body: params.toString(),
    })
    const data = await res.json()
    if (data.code === 0) {
      toast.success('删除成功')
      fetchAks()
    } else {
      toast.error(data.echo || '删除失败')
    }
  } catch (e) {
    console.error('[deleteAk]', e)
    toast.error('删除失败')
  }
}

const openPermission = (ak: AccessKey) => {
  permissionAkId.value = ak.id
  permissionAkName.value = ak.name || ak.access_key
  showPermissionModal.value = true
}

const openLog = (ak: AccessKey) => {
  logAkId.value = ak.id
  logAkName.value = ak.name || ak.access_key
  showLogModal.value = true
}

const cancelDelete = () => {
  showConfirmModal.value = false
  confirmTarget.value = null
}

onMounted(() => {
  fetchAks()
})
</script>

<template>
  <div class="p-6">
    <div class="flex items-center justify-between mb-6">
      <div>
        <h1 class="text-2xl font-bold text-gray-900">AK 管理</h1>
        <p class="text-gray-500 mt-1">管理 AccessKey 访问密钥，用于 API 调用鉴权</p>
      </div>
      <button @click="showCreateModal = true" class="flame-btn flex items-center gap-2">
        <Plus class="w-4 h-4" />
        <span>创建 AK</span>
      </button>
    </div>

    <AkTable
      :aks="aks"
      :loading="loading"
      @toggle="toggleStatus"
      @permission="openPermission"
      @log="openLog"
      @delete="deleteAk"
    />

    <CreateAkModal
      :show="showCreateModal"
      @close="showCreateModal = false"
      @created="fetchAks"
    />

    <PermissionModal
      :show="showPermissionModal"
      :ak-id="permissionAkId"
      :ak-name="permissionAkName"
      @close="showPermissionModal = false"
    />

    <LogModal
      :show="showLogModal"
      :ak-id="logAkId"
      :ak-name="logAkName"
      @close="showLogModal = false"
    />

    <ConfirmModal
      :show="showConfirmModal"
      :title="`确定删除 AK「${confirmTarget?.name || confirmTarget?.access_key}」吗？删除后不可恢复。`"
      @cancel="cancelDelete"
      @confirm="confirmDeleteAk"
    />
  </div>
</template>